"""Gestion de projet de recherche clinique flashcard data - FC4 to FC9"""

COURSES = [
    {
        "id": "sp_gestion_fc4",
        "filename": "fc4.html",
        "folder": "SP_Gestion",
        "title_h1": "Gestion de projet",
        "title_h2": "Structures de soutien \u00e0 la recherche clinique (FC4)",
        "flashcards": [
            ("Pourquoi les structures d\u00e9di\u00e9es \u00e0 la recherche clinique sont-elles n\u00e9cessaires dans les \u00e9tablissements de sant\u00e9 ?", "La dur\u00e9e moyenne de s\u00e9jour a \u00e9t\u00e9 divis\u00e9e par 2 en vingt ans, rendant les services cliniques tr\u00e8s charg\u00e9s par le soin prioritaire. Il est donc difficile d\u2019y mener des recherches sans structures d\u00e9di\u00e9es."),
            ("Quels sont les deux mod\u00e8les qui se sont d\u00e9velopp\u00e9s pour organiser la recherche clinique \u00e0 l\u2019h\u00f4pital ?", "1) Des structures d\u00e9di\u00e9es \u00e0 la recherche (mutualisation de moyens)\n2) Des techniciens de recherche clinique \u00e9parpill\u00e9s dans les services pour d\u00e9charger le personnel soignant."),
            ("Quelles sont les principales structures de soutien \u00e0 la recherche clinique dans les \u00e9tablissements de sant\u00e9 ?", "CIC (Centres d\u2019Investigation Clinique), CRC (Centres de Recherche Clinique), EMRC (\u00c9quipes Mobiles de Recherche Clinique en canc\u00e9rologie), CRB (Centres de Ressources Biologiques), DRCI (D\u00e9l\u00e9gations de Recherche Clinique et de l\u2019Innovation), GIRCI (Groupements Interr\u00e9gionaux de Recherche Clinique et d\u2019Innovation)."),
            ("Quand ont \u00e9t\u00e9 cr\u00e9\u00e9s les premiers CIC ?", "Les premiers CIC ont \u00e9t\u00e9 cr\u00e9\u00e9s en 1992."),
            ("Combien de CIC existe-t-il au niveau national ?", "Il existe 36 centres d\u2019investigation clinique au niveau national."),
            ("Sous quelle double tutelle sont plac\u00e9s les CIC ?", "Les CIC sont sous double tutelle du minist\u00e8re charg\u00e9 de la recherche et du minist\u00e8re charg\u00e9 de la sant\u00e9 (via l\u2019INSERM)."),
            ("Quelles sont les missions principales des CIC ?", "1) Favoriser l\u2019acquisition de nouvelles connaissances scientifiques et m\u00e9dicales\n2) Am\u00e9liorer la prise en charge translationnelle des patients\n3) Acc\u00e9l\u00e9rer la transformation des d\u00e9couvertes fondamentales en applications cliniques et r\u00e9ciproquement."),
            ("Qu\u2019est-ce que la recherche clinique translationnelle ?", "C\u2019est la capacit\u00e9 de faire passer les r\u00e9sultats de la recherche fondamentale vers des applications cliniques au profit des malades."),
            ("O\u00f9 sont implant\u00e9s les CIC ?", "Les CIC sont implant\u00e9s dans les centres hospitalo-universitaires (CHU)."),
            ("Les CIC sont-ils r\u00e9serv\u00e9s aux investigateurs acad\u00e9miques ?", "Non, les CIC sont des structures ouvertes aux investigateurs et promoteurs de toute origine, acad\u00e9miques, institutionnels comme industriels."),
            ("Sur quels types de recherches les CIC prennent-ils en charge ?", "Recherches sur la personne humaine (saine ou malade), les donn\u00e9es de sant\u00e9 recueillies dans le cadre des soins, les collections d\u2019\u00e9chantillons biologiques, et les outils en technologie pour la sant\u00e9."),
            ("Combien de modules th\u00e9matiques les CIC sont-ils organis\u00e9s et en combien de r\u00e9seaux ?", "Les CIC sont organis\u00e9s en 54 modules th\u00e9matiques r\u00e9partis en r\u00e9seaux th\u00e9matiques."),
            ("Quels sont les quatre types de modules des CIC ?", "1) 27 modules plurith\u00e9matiques (recherche clinique translationnelle)\n2) 9 modules d\u2019\u00e9pid\u00e9miologie clinique\n3) 10 modules de bioth\u00e9rapies (th\u00e9rapie cellulaire et g\u00e9nique)\n4) 8 modules d\u2019innovations technologiques."),
            ("Que font les modules plurith\u00e9matiques des CIC ?", "Ils d\u00e9veloppent la recherche clinique translationnelle, avec une activit\u00e9 cibl\u00e9e sur les axes prioritaires du site d\u2019accueil. Ils disposent de m\u00e9decins, infirmi\u00e8res, lits, consultations, laboratoire pour accueillir les sujets."),
            ("Quelle est la particularit\u00e9 des modules d\u2019\u00e9pid\u00e9miologie clinique ?", "Ils n\u2019accueillent pas le patient directement et s\u2019int\u00e9ressent \u00e0 des bases de donn\u00e9es existantes. Ils regroupent \u00e9pid\u00e9miologistes, m\u00e9thodologistes, biostatisticiens et TECs."),
            ("Que font les modules de bioth\u00e9rapies ?", "Ils d\u00e9veloppent des protocoles de th\u00e9rapie cellulaire et g\u00e9nique, sp\u00e9cialis\u00e9s dans les m\u00e9dicaments vivants, issus de la recherche fondamentale et translationnelle au service des maladies rares et de la vaccinologie."),
            ("Que font les modules d\u2019innovations technologiques ?", "Ils acc\u00e9l\u00e8rent le passage de l\u2019innovation technologique vers la prise en charge diagnostique et th\u00e9rapeutique : dispositifs m\u00e9dicaux, biomat\u00e9riaux, biomarqueurs, imagerie."),
            ("Depuis quelle ann\u00e9e certains CIC sont-ils regroup\u00e9s en r\u00e9seaux th\u00e9matiques ?", "Depuis 2005, pour assurer une meilleure coordination des forces de recherche et des capacit\u00e9s d\u2019accueil."),
            ("Citez au moins cinq r\u00e9seaux th\u00e9matiques des CIC.", "Cardiovasculaire, gastro-ent\u00e9rologie et h\u00e9patologie, neurosciences, p\u00e9diatrie, thrombose, vaccinologie, innovations technologiques, \u00e9pid\u00e9miologie clinique, gyn\u00e9cologie-obst\u00e9trique."),
            ("Pourquoi les r\u00e9seaux th\u00e9matiques des CIC sont-ils utiles ?", "Ils aident aux inclusions de patients et permettent d\u2019avoir un protocole plus efficace et rapide gr\u00e2ce \u00e0 une meilleure coordination entre sites."),
            ("Quel organisme pilote les CIC avec le MSP ?", "L\u2019INSERM anime et pilote les CIC conjointement avec le Minist\u00e8re de la Sant\u00e9 et de la Pr\u00e9vention (MSP)."),
            ("\u00c0 combien s\u2019\u00e9levait la dotation annuelle du MSP pour les CIC en 2022 ?", "La dotation fl\u00e9ch\u00e9e s\u2019\u00e9levait \u00e0 25,5 millions d\u2019euros en 2022."),
            ("\u00c0 quoi sert la dotation annuelle du MSP pour les CIC ?", "Elle permet de payer le personnel de base et de trouver les sources compl\u00e9mentaires lors des appels \u00e0 projets pour recruter du personnel suppl\u00e9mentaire."),
            ("Tous les combien d\u2019ann\u00e9es les CIC sont-ils \u00e9valu\u00e9s ?", "Tous les cinq ans, chaque CIC est soumis \u00e0 une \u00e9valuation scientifique par le HCERES."),
            ("Qu\u2019est-ce que le HCERES ?", "Le Haut Conseil de l\u2019\u00c9valuation de la Recherche et de l\u2019Enseignement Sup\u00e9rieur, une instance ind\u00e9pendante qui \u00e9value les \u00e9quipes de recherche et la qualit\u00e9 de l\u2019enseignement."),
            ("Quel bilan peut-on dresser des CIC ?", "Bilan tr\u00e8s positif : contribution \u00e0 l\u2019essor de la recherche clinique, structuration dans la majorit\u00e9 des CHU, am\u00e9lioration de la qualit\u00e9 (interface fondamental-soin, m\u00e9thodologie, professionnalisation), plus de 10 000 publications scientifiques."),
            ("Combien de publications scientifiques ont d\u00e9coul\u00e9 de l\u2019activit\u00e9 des CIC ?", "Plus de 10 000 publications scientifiques, ce qui a conduit plusieurs pays \u00e0 adopter le mod\u00e8le fran\u00e7ais des CIC."),
            ("Quelles sont les \u00e9volutions du mod\u00e8le des CIC ?", "La fin de la logique des modules remplac\u00e9s par des domaines d\u2019activit\u00e9s sp\u00e9cifiques et adaptables, la d\u00e9finition de comp\u00e9tences socles partag\u00e9es, et le renforcement des liens avec l\u2019environnement local."),
            ("Qu\u2019apportent les CRC (Centres de Recherche Clinique) ?", "Les CRC apportent un appui m\u00e9thodologique et organisationnel \u00e0 la r\u00e9alisation des essais cliniques : conception et mise en \u0153uvre des protocoles, suivi r\u00e9glementaire et \u00e9thique, gestion des bases de donn\u00e9es."),
            ("Quand a \u00e9t\u00e9 cr\u00e9\u00e9 le CIC de l\u2019h\u00f4pital Henri-Mondor ?", "Le CIC d\u2019Henri-Mondor a \u00e9t\u00e9 cr\u00e9\u00e9 en 2002."),
            ("Quelle est la surface d\u00e9di\u00e9e \u00e0 la recherche au CIC d\u2019Henri-Mondor ?", "450 m\u00e8tres carr\u00e9s de locaux d\u00e9di\u00e9s \u00e0 la recherche."),
            ("Quels \u00e9quipements le CIC d\u2019Henri-Mondor comprend-il ?", "2 boxes de consultation, 3 lits d\u2019h\u00f4pital de jour (HDJ) d\u00e9di\u00e9s, 1 poste de soins pour les infirmi\u00e8res, une salle \u00e0 manger pour le patient valide."),
            ("Pourquoi le CIC d\u2019Henri-Mondor n\u2019entre-t-il pas en comp\u00e9tition avec la fili\u00e8re soin ?", "La r\u00e9ception de patients par jour est inf\u00e9rieure \u00e0 celle des services traditionnels, il n\u2019y a pas d\u2019attente, et cela permet la fid\u00e9lisation des patients."),
            ("Quels professionnels travaillent dans un CIC ?", "Infirmi\u00e8res de recherche, aides-soignantes, m\u00e9decins de recherche clinique, m\u00e9decins des services hospitaliers, techniciens de recherche clinique, psychologues de recherche, ing\u00e9nieurs, et les ARC moniteurs."),
            ("Quelle formation sp\u00e9cifique est requise pour les infirmi\u00e8res de recherche dans un CIC ?", "Une exp\u00e9rience de soins et un DU (Dipl\u00f4me Universitaire) de recherche clinique."),
            ("Quel est le r\u00f4le des techniciens de recherche clinique (TRC) dans un CIC ?", "Ils veillent au bon d\u00e9roulement de l\u2019\u00e9tude, sont en contact avec les patients, et sont impliqu\u00e9s dans la mise en place et le suivi des protocoles. Ils ont une formation scientifique non m\u00e9dicale."),
            ("Que repr\u00e9sentent les ARC moniteurs accueillis au CIC ?", "Ce sont les repr\u00e9sentants du promoteur. Ils contr\u00f4lent le bon d\u00e9roulement de l\u2019\u00e9tude."),
            ("Dans le cadre de la recherche, qui fait la proposition initiale au patient ?", "C\u2019est le m\u00e9decin qui propose la participation \u00e0 l\u2019\u00e9tude au patient (m\u00e9decin vers patient), contrairement au cadre du soin o\u00f9 le patient est demandeur."),
            ("Quels sont les avantages potentiels pour un patient participant \u00e0 une recherche clinique ?", "Un suivi clinique plus rapproch\u00e9 et un acc\u00e8s \u00e0 des mol\u00e9cules innovantes."),
            ("Quels sont les droits du patient dans le cadre de la recherche clinique ?", "Droit de refus sans impact sur le soin, droit de retrait secondaire, protection par le secret m\u00e9dical et un num\u00e9ro d\u2019anonymat, assurance, et la garantie d\u2019\u00eatre soign\u00e9 au maximum des connaissances."),
            ("Qu\u2019est-ce que le consentement \u00e9clair\u00e9 ?", "C\u2019est un \u00e9l\u00e9ment essentiel et obligatoire : apr\u00e8s explication d\u00e9taill\u00e9e du protocole et un d\u00e9lai de r\u00e9flexion, le patient signe volontairement un document formalisant son accord \u00e0 participer."),
            ("Quelle est la diff\u00e9rence entre le formulaire de non-opposition et le consentement \u00e9clair\u00e9 ?", "Le formulaire de non-opposition est utilis\u00e9 quand il n\u2019y a pas de traitement exp\u00e9rimental ni acte invasif (collecte d\u2019informations uniquement). Le consentement \u00e9clair\u00e9 est exig\u00e9 quand l\u2019\u00e9tude implique un traitement exp\u00e9rimental, un dispositif m\u00e9dical ou des actes invasifs."),
            ("Comment se d\u00e9roule le suivi m\u00e9dical d\u2019un patient au cours d\u2019une \u00e9tude clinique ?", "Recueil d\u2019informations, surveillance de l\u2019\u00e9volution clinique, prescription d\u2019examens pr\u00e9vus par le protocole, administration et ajustement des traitements, et surveillance de la tol\u00e9rance au traitement."),
            ("Dans quel d\u00e9lai les \u00e9v\u00e9nements ind\u00e9sirables graves doivent-ils \u00eatre d\u00e9clar\u00e9s ?", "Les \u00e9v\u00e9nements ind\u00e9sirables graves doivent \u00eatre d\u00e9clar\u00e9s dans les 24 heures."),
            ("Comment sont collect\u00e9s les \u00e9v\u00e9nements ind\u00e9sirables mineurs ?", "Ils font l\u2019objet d\u2019une collecte syst\u00e9matique, m\u00eame en l\u2019absence de plainte du patient."),
            ("Quelles sont les trois motivations principales des patients pour participer \u00e0 une \u00e9tude clinique ?", "1) Volont\u00e9 de contribuer \u00e0 la recherche (sentiment d\u2019\u00e9change \u00e9quitable)\n2) Situation th\u00e9rapeutique sans alternative (impasse th\u00e9rapeutique)\n3) Suivi m\u00e9dical renforc\u00e9 (plus r\u00e9gulier et approfondi)."),
            ("\u00c0 quoi sert le questionnaire de satisfaction dans un CIC ?", "C\u2019est un outil d\u2019am\u00e9lioration permettant d\u2019\u00e9valuer la clart\u00e9 des informations re\u00e7ues, l\u2019accessibilit\u00e9 des professionnels et l\u2019accompagnement tout au long du protocole. Il est anonyme."),
            ("Avec quels acteurs le CIC interagit-il ?", "Les membres de l\u2019\u00e9quipe, les patients et familles, les sp\u00e9cialistes, le service d\u2019imagerie, la PUI (pharmacie \u00e0 usage int\u00e9rieur), les ARC moniteurs, et d\u2019autres intervenants si n\u00e9cessaire."),
            ("Un CIC est-il un lieu de soins ?", "Non, un CIC est un lieu de recherche, pas un lieu de soins. L\u2019organisation veille cependant \u00e0 \u00e9viter toute rupture dans la prise en charge m\u00e9dicale habituelle."),
            ("Pourquoi le monitoring est-il fondamental en recherche clinique par rapport \u00e0 la recherche fondamentale ?", "En recherche fondamentale, les donn\u00e9es ne font pas l\u2019objet d\u2019une validation externe syst\u00e9matique. En recherche clinique, les r\u00e9sultats peuvent aboutir \u00e0 la commercialisation d\u2019un m\u00e9dicament, d\u2019o\u00f9 un processus rigoureux de monitoring."),
            ("Quel est le r\u00f4le du technicien de recherche clinique au quotidien ?", "Il est pr\u00e9sent lors des consultations, organise les examens, g\u00e8re les rendez-vous et s\u2019assure de la bonne ex\u00e9cution du protocole. Sa proximit\u00e9 avec les patients est telle qu\u2019ils retiennent souvent son nom plus facilement que celui du m\u00e9decin."),
            ("Quelles mesures de s\u00e9curit\u00e9 sont mises en place dans un CIC ?", "Autorisation de lieu de l\u2019ARS, formation du personnel aux gestes d\u2019urgences, convention avec la r\u00e9animation, simulation d\u2019exercice, chariot d\u2019urgence disponible."),
            ("Quelles recherches ne peuvent pas \u00eatre r\u00e9alis\u00e9es dans un CIC ?", "Les premi\u00e8res administrations \u00e0 l\u2019homme (phase I) qui n\u00e9cessitent des structures sp\u00e9cialis\u00e9es, et les \u00e9tudes sur volontaires sains dans les services de sp\u00e9cialit\u00e9."),
            ("Quelles structures ont besoin d\u2019une autorisation de lieu ?", "Celles r\u00e9alisant des actes hors de leur activit\u00e9 habituelle, \u00e9tudiant une pathologie hors sp\u00e9cialit\u00e9, incluant des volontaires sains hors sp\u00e9cialit\u00e9, menant une recherche hors lieu de soins (CIC), ou r\u00e9alisant des premi\u00e8res administrations \u00e0 l\u2019homme."),
            ("Quelle est la proc\u00e9dure pour obtenir une autorisation de lieu ?", "Demande \u00e0 l\u2019ARS, dossier de 20-30 pages d\u00e9crivant les processus de s\u00e9curit\u00e9, puis visite sur site de l\u2019ARS."),
            ("Quelle est la dur\u00e9e de validit\u00e9 d\u2019une autorisation de lieu ?", "3 ans si le site inclut des \u00e9tudes de premi\u00e8res administrations \u00e0 l\u2019homme, 7 ans sinon."),
            ("Quelle nouvelle obligation est impos\u00e9e aux CIC d\u2019ici 2026 ?", "La mise en place d\u2019un syst\u00e8me de management de la qualit\u00e9 conforme \u00e0 la norme ISO 9001, avec identification des processus clefs, \u00e9tablissement de proc\u00e9dures et un manuel qualit\u00e9."),
            ("Qu\u2019est-ce que la norme ISO 9001 appliqu\u00e9e aux CIC ?", "Norme d\u00e9finissant des exigences pour un syst\u00e8me de management de la qualit\u00e9 : identifier des processus clefs, \u00e9tablir des proc\u00e9dures, impliquer l\u2019ensemble de l\u2019\u00e9quipe, encadr\u00e9e par un ing\u00e9nieur qualit\u00e9."),
            ("Qu\u2019est-ce qu\u2019un CRC et quels sont ses objectifs ?", "Un Centre de Recherche Clinique, cr\u00e9\u00e9 il y a une dizaine d\u2019ann\u00e9es, visant l\u2019am\u00e9lioration de la qualit\u00e9 des essais, l\u2019acc\u00e9l\u00e9ration des recrutements, l\u2019am\u00e9lioration de la s\u00e9curit\u00e9 des patients et la gestion mutualis\u00e9e du personnel de recherche."),
            ("Quelle est la diff\u00e9rence principale entre un CRC et un CIC ?", "Les CRC ont \u00e0 peu pr\u00e8s les m\u00eames missions que les CIC mais le plan administratif et le pilotage sont diff\u00e9rents."),
            ("Qu\u2019est-ce qu\u2019une EMRC et dans quel contexte a-t-elle \u00e9t\u00e9 cr\u00e9\u00e9e ?", "Une \u00c9quipe Mobile de Recherche Clinique en Canc\u00e9rologie, issue du premier Plan Cancer et des appels \u00e0 projets de 2004 et 2006."),
            ("Combien d\u2019EMRC sont actives et par qui sont-elles coordonn\u00e9es ?", "26 EMRC actives, coordonn\u00e9es par les GIRCI."),
            ("Quelle est la sp\u00e9cificit\u00e9 des EMRC par rapport aux ARC ?", "Leur r\u00f4le est similaire aux ARC mais ils se d\u00e9placent sur plusieurs sites (entre 145 et 200 \u00e9tablissements) et leur activit\u00e9 est exclusivement d\u00e9di\u00e9e \u00e0 la canc\u00e9rologie."),
            ("Citez au moins quatre missions des EMRC.", "1) Aider \u00e0 la mise en place des essais\n2) Assurer le lien avec le promoteur\n3) G\u00e9rer les contacts avec la Direction et la Pharmacie\n4) Participer au rep\u00e9rage et \u00e0 l\u2019inclusion des patients\n5) Aider au remplissage des CRF et au monitoring."),
            ("Qu\u2019est-ce qu\u2019un CRB (Centre de Ressources Biologiques) ?", "Une plateforme de gestion d\u2019\u00e9chantillons biologiques associ\u00e9s \u00e0 des donn\u00e9es cliniques, pathologiques, biologiques ou mol\u00e9culaires. Son appellation est apparue en 1999 \u00e0 l\u2019issue d\u2019un travail de l\u2019OCDE."),
            ("Quelles sont les missions principales d\u2019un CRB ?", "G\u00e9rer les collections biologiques (r\u00e9ception, pr\u00e9paration, conservation), les distribuer aux chercheurs, effectuer des prestations (aliquotage, centrifugation, extraction d\u2019ADN), et garantir la tra\u00e7abilit\u00e9 et la surveillance des temp\u00e9ratures 24h/24."),
            ("Quelles garanties un CRB doit-il offrir ?", "La protection des patients (consentement, anonymisation), le respect de la r\u00e9glementation, et la qualit\u00e9 des \u00e9chantillons associ\u00e9s aux donn\u00e9es."),
            ("Qu\u2019est-ce qu\u2019une URC (Unit\u00e9 de Recherche Clinique) ?", "Structure de support d\u00e9di\u00e9e \u00e0 la recherche qui accompagne les m\u00e9decins pour mener leurs projets, assurant le pilotage, la coordination et la gestion des \u00e9tudes cliniques acad\u00e9miques et industrielles."),
            ("Quels professionnels composent une URC ?", "Techniciens d\u2019\u00e9tude clinique, attach\u00e9s de recherche clinique, coordinateurs d\u2019\u00e9tude clinique, chefs de projet, data managers, biostatisticiens."),
            ("Quelles sont les missions principales d\u2019une URC ?", "Appui m\u00e9thodologique, suivi biostatistique, accompagnement de la conception des programmes de recherche, suivi et contr\u00f4le de la qualit\u00e9, gestion des donn\u00e9es, et coordination des activit\u00e9s de recherche."),
            ("Qu\u2019est-ce que la DRCI ?", "La Direction de la Recherche Clinique et de l\u2019Innovation, charg\u00e9e de piloter et suivre l\u2019ensemble des projets de recherche et d\u2019innovation au sein de l\u2019AP-HP."),
            ("Quelles expertises la DRCI poss\u00e8de-t-elle ?", "L\u2019aide \u00e0 la d\u00e9tection, protection et valorisation des innovations en milieu hospitalier, et la mise en place de partenariats R&D dans le cadre de projets collaboratifs."),
            ("Comment la DRCI accompagne-t-elle les investigateurs ?", "Conception, financement, suivi des autorisations, r\u00e9alisation, surveillance et contr\u00f4le qualit\u00e9 des protocoles, valorisation des r\u00e9sultats (publications, brevets), contractualisation et financement d\u2019actions de soutien."),
            ("Quelle est la composition de la DRCI de l\u2019AP-HP ?", "6 p\u00f4les d\u2019activit\u00e9s (site Saint-Louis), 12 URC r\u00e9parties dans les groupes hospitaliers, 1 URC Eco, 1 DEC, 1 CEDM, 1 Centre de Pharmaco-\u00e9pid\u00e9miologie (CEPHEPI)."),
            ("Que signifie MERRI dans le contexte de la DRCI ?", "Missions d\u2019Enseignement, de Recherche, de R\u00e9f\u00e9rence et d\u2019Innovation : enveloppes de financement attribu\u00e9es aux \u00e9tablissements hospitaliers."),
            ("Qu\u2019est-ce qu\u2019un GIRCI ?", "Un Groupement Interr\u00e9gional de Recherche Clinique et d\u2019Innovation, organisme fran\u00e7ais charg\u00e9 d\u2019assurer des missions d\u2019animation et de soutien \u00e0 la recherche."),
            ("Combien de GIRCI existent et depuis quand ?", "7 GIRCI cr\u00e9\u00e9s depuis 2011."),
            ("Quelles sont les missions des GIRCI ?", "Animation territoriale, appui aux \u00e9tablissements sans structure de recherche, information et orientation des professionnels de sant\u00e9, et formation \u00e0 la recherche appliqu\u00e9e en sant\u00e9 et \u00e0 l\u2019innovation."),
            ("Les GIRCI sont-ils promoteurs de projets de recherche ?", "Non, les GIRCI ne sont pas promoteurs de projets de recherche. Leurs actions sont compl\u00e9mentaires de celles des dispositifs d\u2019appui des CHU."),
            ("Quelle est la mission principale de l\u2019h\u00f4pital ?", "La mission principale de l\u2019h\u00f4pital est de soigner les patients. La recherche vient en compl\u00e9ment."),
            ("Qu\u2019est-ce que la DUR&I ?", "La D\u00e9l\u00e9gation Unique de Recherche et d\u2019Innovation, qui facilite la gestion des projets de recherche clinique multi-centriques en simplifiant les d\u00e9marches administratives et en harmonisant les protocoles."),
            ("Quel est le r\u00f4le du m\u00e9decin de recherche clinique dans un CIC ?", "Il a une exp\u00e9rience de soins et participe aux consultations de recherche, au recueil de donn\u00e9es et au suivi des patients dans le cadre des protocoles."),
            ("Pourquoi les m\u00e9decins des services hospitaliers sont-ils sollicit\u00e9s dans un CIC ?", "Ils sont sollicit\u00e9s pour leur expertise sp\u00e9cifique selon la pathologie \u00e9tudi\u00e9e."),
            ("Quel est le r\u00f4le du psychologue de recherche dans un CIC ?", "Il intervient dans le cadre d\u2019\u00e9tudes en psychiatrie ou en neuropsychiatrie."),
            ("Qu\u2019est-ce qu\u2019une consultation de recherche structur\u00e9e ?", "Une consultation avec recueil de donn\u00e9es pr\u00e9\u00e9tablies, examens d\u2019imagerie pr\u00e9sp\u00e9cifi\u00e9s, v\u00e9rification de l\u2019observance, d\u00e9livrance du m\u00e9dicament de recherche, recherche d\u2019\u00e9v\u00e9nements ind\u00e9sirables et de signes d\u2019aggravation."),
            ("Que doit-on rechercher lors du suivi d\u2019un patient dans une \u00e9tude clinique ?", "Les \u00e9v\u00e9nements ind\u00e9sirables li\u00e9s au traitement, les signes d\u2019aggravation ou d\u2019instabilit\u00e9 de la pathologie, et les signes d\u2019une autre pathologie. Tout doit \u00eatre r\u00e9pertori\u00e9 dans le dossier."),
            ("Que se passe-t-il en cas d\u2019anomalie pr\u00e9occupante chez un patient d\u2019\u00e9tude clinique ?", "Le patient peut \u00eatre r\u00e9orient\u00e9 vers son m\u00e9decin g\u00e9n\u00e9raliste, un sp\u00e9cialiste ou un service d\u2019urgence si n\u00e9cessaire."),
            ("Que signifie PUI dans le contexte d\u2019un CIC ?", "Pharmacie \u00e0 Usage Int\u00e9rieur : c\u2019est l\u2019entit\u00e9 qui d\u00e9livre le m\u00e9dicament de recherche."),
            ("O\u00f9 peut-on trouver la liste des \u00e9tablissements ayant une autorisation de lieu ?", "Sur le site de l\u2019Agence R\u00e9gionale de Sant\u00e9 (ARS), qui r\u00e9pertorie les structures avec attestation de lieu, les sp\u00e9cialit\u00e9s couvertes et les conditions sp\u00e9cifiques."),
            ("Qu\u2019est-ce que l\u2019assurance qualit\u00e9 dans le contexte des CIC ?", "C\u2019est l\u2019am\u00e9lioration de la qualit\u00e9 de la recherche \u00e0 l\u2019interface du fondamental et du soin, incluant m\u00e9thodologie, technologie, professionnalisation et proc\u00e9dures de contr\u00f4le."),
            ("Pourquoi la confiance est-elle importante dans la relation patient-CIC ?", "Le CIC re\u00e7oit moins de patients par jour que les services traditionnels, permettant de passer plus de temps avec chaque patient et d\u2019\u00e9tablir une relation de confiance essentielle \u00e0 la fid\u00e9lisation et au bon d\u00e9roulement de l\u2019\u00e9tude."),
            ("Qu\u2019est-ce que signifie HDJ dans un CIC ?", "H\u00f4pital De Jour : le CIC d\u2019Henri-Mondor dispose de 3 lits d\u2019HDJ d\u00e9di\u00e9s \u00e0 la recherche."),
        ]
    },
    {
        "id": "sp_gestion_fc5",
        "filename": "fc5.html",
        "folder": "SP_Gestion",
        "title_h1": "Gestion de projet",
        "title_h2": "Mise en place d\u2019un essai clinique (FC5)",
        "flashcards": [
            ("Pourquoi la coordination est-elle une difficult\u00e9 majeure en recherche clinique ?", "Elle n\u00e9cessite la coordination d\u2019intervenants de professions diff\u00e9rentes (m\u00e9decins, infirmi\u00e8res, TRC, TEC, radiologues, techniciens de laboratoire) ayant des fonctions diff\u00e9rentes."),
            ("Quel est le point clef d\u2019une recherche r\u00e9ussie ?", "La motivation des personnels pour les inclusions des patients."),
            ("Quel est le r\u00f4le principal de la r\u00e9union de mise en place ?", "Organiser le protocole : d\u00e9finir en pratique la coordination et le mode de fonctionnement local de l\u2019\u00e9tude, adapt\u00e9 aux contraintes du service."),
            ("Quand doit avoir lieu la r\u00e9union de mise en place ?", "Apr\u00e8s l\u2019obtention des autorisations n\u00e9cessaires (promotion, avis du CPP, autorisation de l\u2019ANSM) et avant la premi\u00e8re inclusion dans le centre."),
            ("La r\u00e9union de mise en place a-t-elle lieu une seule fois ?", "Du point de vue d\u2019un centre unique, elle a lieu une seule fois. Du point de vue du promoteur, il doit effectuer plusieurs mises en place (une par centre participant)."),
            ("Qui doit assister \u00e0 la r\u00e9union de mise en place ?", "L\u2019ensemble des personnels impliqu\u00e9s : ARC, chef de projet, m\u00e9decin du promoteur, m\u00e9decin investigateur, infirmi\u00e8res de recherche, TRC, technicien de laboratoire, ARC monitoring, pharmacien (si m\u00e9dicament), radiologue (si explorations compl\u00e9mentaires)."),
            ("Pourquoi est-il pr\u00e9f\u00e9rable de r\u00e9unir tout le monde en m\u00eame temps ?", "Plus il y a de personnes concern\u00e9es pr\u00e9sentes, mieux l\u2019\u00e9tude sera structur\u00e9e et organis\u00e9e."),
            ("Les r\u00e9unions de mise en place peuvent-elles se faire en distanciel ?", "Oui pour les \u00e9tudes simples (ex : suivi de cohortes), mais une r\u00e9union en pr\u00e9sentiel reste une meilleure garantie."),
            ("Quels sujets sont abord\u00e9s lors de la r\u00e9union de mise en place ?", "Dispensation du traitement, proc\u00e9dure de prise de rendez-vous, pr\u00e9sentation du protocole, crit\u00e8res d\u2019inclusion et de non-inclusion, questions de logistique."),
            ("Pourquoi ne faut-il pas faire de multiples sous-mises en place ?", "Faire des sous-r\u00e9unions s\u00e9par\u00e9es (investigateur, puis pharmacie, puis radiologie) est l\u00e9galement valide mais inefficace en pratique. Il faut une mise en place globale."),
            ("Qu\u2019est-ce que le cahier investigateur ?", "Un classeur regroupant l\u2019ensemble des documents administratifs relatifs \u00e0 l\u2019\u00e9tude, conserv\u00e9 par le site investigateur. Il est souvent remis lors de la r\u00e9union de mise en place."),
            ("Qui coordonne et dirige la mise en place ?", "L\u2019attach\u00e9 de recherche clinique (ARC) coordonne et dirige la mise en place."),
            ("Quels documents administratifs figurent dans le cahier investigateur ?", "Avis CPP, autorisation ANSM, autorisation CNIL, exemplaire d\u2019assurance, fiche de d\u00e9l\u00e9gation de t\u00e2ches, correspondance de l\u2019\u00e9tude, recommandations BPC, documents \u00e9volutifs en fonction des amendements."),
            ("Pourquoi faut-il une tra\u00e7abilit\u00e9 de la r\u00e9union de mise en place ?", "Pour savoir qui a assist\u00e9 \u00e0 la r\u00e9union. Une attestation de pr\u00e9sence est \u00e9tablie."),
            ("Qu\u2019est-ce que le CPP et comment est-il d\u00e9sign\u00e9 ?", "Le Comit\u00e9 de Protection des Personnes. Depuis 2-3 ans, il est d\u00e9sign\u00e9 par tirage au sort automatis\u00e9 afin de limiter les conflits d\u2019int\u00e9r\u00eats."),
            ("Quel est le r\u00f4le de l\u2019ANSM avant un essai clinique ?", "L\u2019ANSM doit donner un avis favorable en analysant le protocole : design, crit\u00e8res d\u2019inclusion, contre-indications, bases scientifiques suffisantes."),
            ("Qu\u2019est-ce que la CNIL dans le contexte d\u2019un essai clinique ?", "La Commission Nationale de l\u2019Informatique et des Libert\u00e9s. Le fichier informatif doit \u00eatre d\u00e9velopp\u00e9 et g\u00e9r\u00e9 conform\u00e9ment \u00e0 ses exigences."),
            ("Qu\u2019est-ce que la MR-001 ?", "Une m\u00e9thodologie de r\u00e9f\u00e9rence pour les \u00e9tudes interventionnelles avec unit\u00e9 de recueil du consentement des patients."),
            ("Qu\u2019est-ce que la MR-003 ?", "Une m\u00e9thodologie de r\u00e9f\u00e9rence pour les \u00e9tudes non interventionnelles avec recueil de la non-opposition du patient."),
            ("Pourquoi une assurance est-elle n\u00e9cessaire pour un protocole interventionnel ?", "Pour couvrir et prot\u00e9ger les patients face aux risques et al\u00e9as potentiels li\u00e9s \u00e0 la recherche, y compris les accidents li\u00e9s \u00e0 la prise du m\u00e9dicament \u00e0 l\u2019essai et pr\u00e9voir l\u2019indemnisation des patients."),
            ("Qu\u2019est-ce que la fiche de d\u00e9l\u00e9gation de t\u00e2ches ?", "Un tableau indiquant pour chaque participant ses t\u00e2ches d\u00e9l\u00e9gu\u00e9es par l\u2019investigateur principal (signature du consentement, examen clinique, vaccination, pr\u00e9l\u00e8vements, remplissage du CRF, etc.), valid\u00e9 et sign\u00e9 par l\u2019IP."),
            ("Pourquoi d\u00e9clarer l\u2019\u00e9tude sur ClinicalTrials.gov ?", "Pour la transparence vis-\u00e0-vis des patients, pour d\u00e9terminer en amont le crit\u00e8re d\u2019\u00e9valuation principal (non modifiable ensuite), et parce que les journaux am\u00e9ricains exigent cet enregistrement pour publier."),
            ("La d\u00e9claration sur ClinicalTrials.gov est-elle r\u00e9glementairement obligatoire ?", "Non, elle n\u2019est pas r\u00e9glementairement obligatoire mais pratiquement indispensable car les journaux n\u2019acceptent pas de publier un essai sans r\u00e9f\u00e9rencement."),
            ("Qu\u2019est-ce qu\u2019Eudravigilance ?", "Une base europ\u00e9enne de d\u00e9claration des effets ind\u00e9sirables survenant dans un essai clinique, permettant de regrouper tous les effets ind\u00e9sirables d\u2019une m\u00eame mol\u00e9cule participant \u00e0 plusieurs essais."),
            ("\u00c0 quoi sert Eudravigilance ?", "Elle permet d\u2019avoir une vue globale des effets ind\u00e9sirables d\u2019une mol\u00e9cule, m\u00eame s\u2019ils surviennent dans diff\u00e9rents essais en m\u00eame temps."),
            ("Quand doit-on s\u2019inscrire sur Eudravigilance ?", "L\u2019essai doit \u00eatre inscrit avant de commencer l\u2019\u00e9tude."),
            ("Qu\u2019est-ce que le DICV utilis\u00e9 comme exemple dans le cours ?", "Le D\u00e9ficit Immunitaire Commun Variable, un des d\u00e9ficits immunitaires primitifs les plus fr\u00e9quents (1/10 000 \u00e0 1/20 000), caract\u00e9ris\u00e9 par une hypogammaglobulin\u00e9mie et des infections bact\u00e9riennes r\u00e9cidivantes."),
            ("Quel est le traitement du DICV ?", "Administration substitutive \u00e0 vie d\u2019immunoglobulines intraveineuses (IgIV) ou sous-cutan\u00e9es permettant de r\u00e9duire la fr\u00e9quence des infections."),
            ("Dans l\u2019essai exemple, quel \u00e9tait le design de l\u2019\u00e9tude ?", "Essai th\u00e9rapeutique interventionnel, randomis\u00e9 (deux groupes parall\u00e8les), multicentrique (9 centres), phase II pr\u00e9coce, 70 patients (24 groupe 1, 46 groupe 2, randomisation d\u00e9s\u00e9quilibr\u00e9e), promoteur INSERM."),
            ("Quelle est la diff\u00e9rence entre crit\u00e8re d\u2019\u00e9valuation principal et secondaire ?", "Le crit\u00e8re principal est l\u2019\u00e9l\u00e9ment majeur sur lequel on conclut l\u2019efficacit\u00e9. Les crit\u00e8res secondaires sont indicatifs : on ne peut pas conclure l\u2019efficacit\u00e9 d\u2019un traitement sur les crit\u00e8res secondaires seuls."),
            ("Citez des exemples de crit\u00e8res d\u2019inclusion de l\u2019essai DICV.", "Sujets \u00e2g\u00e9s de 18 \u00e0 60 ans, DICV selon OMS, trait\u00e9s par IgIV mensuelles, absence d\u2019infection aigu\u00eb, consentement \u00e9clair\u00e9 sign\u00e9."),
            ("Qu\u2019est-ce qu\u2019un flow chart dans un protocole ?", "Un tableau synth\u00e9tisant les actes \u00e0 r\u00e9aliser \u00e0 chaque visite, facilitant la compr\u00e9hension du d\u00e9roulement de l\u2019\u00e9tude. Il est pr\u00e9f\u00e9r\u00e9 \u00e0 la r\u00e9daction car plus pratique."),
            ("Qu\u2019est-ce que le CRF ?", "Le Case Report Form (cahier de recueil de donn\u00e9es) : document destin\u00e9 \u00e0 recueillir les donn\u00e9es n\u00e9cessaires \u00e0 l\u2019essai clinique, sous forme papier ou \u00e9lectronique."),
            ("Les CRF papier sont-ils encore utilis\u00e9s ?", "Les versions imprim\u00e9es se font rares, mais restent fr\u00e9quentes pour les protocoles monocentriques."),
            ("Qu\u2019est-ce qu\u2019un E-CRF et quel logiciel est utilis\u00e9 \u00e0 l\u2019AP-HP ?", "Un CRF \u00e9lectronique, saisi directement ou apr\u00e8s la visite. L\u2019AP-HP utilise le logiciel CleanWeb, simple d\u2019utilisation."),
            ("Quels sont les avantages d\u2019un E-CRF ?", "Saisie automatique de la base, g\u00e9n\u00e9ration automatique de questions en cas de valeurs douteuses."),
            ("Pourquoi les normes de laboratoire diff\u00e8rent-elles entre h\u00f4pitaux ?", "Chaque h\u00f4pital ou laboratoire a ses propres normes pour chaque valeur. On interpr\u00e8te les r\u00e9sultats en fonction des normes locales."),
            ("Qu\u2019est-ce que le circuit du m\u00e9dicament dans un essai clinique ?", "L\u2019organisation du stockage, de la distribution, et du devenir des seringues usag\u00e9es (ou autres formes) du m\u00e9dicament exp\u00e9rimental."),
            ("Qu\u2019est-ce que le circuit des pr\u00e9l\u00e8vements sanguins ?", "L\u2019organisation du devenir des tubes de pr\u00e9l\u00e8vements, de l\u2019arriv\u00e9e \u00e0 la centrifugation et au stockage."),
            ("D\u00e9crivez le mode op\u00e9ratoire simplifi\u00e9 pour la gestion des pr\u00e9l\u00e8vements de l\u2019essai exemple.", "Arriv\u00e9e de 2 tubes secs de 5 ml, coagulation 30 min minimum, centrifugation \u00e0 3000 tr/min pendant 15 min \u00e0 4\u00b0C, 0,5 ml de s\u00e9rum dans 3 cryotubes, un 4\u00e8me aliquot Biobase, placement \u00e0 -80\u00b0C."),
            ("Quand doit-on effectuer le rappel r\u00e9glementaire lors de la mise en place ?", "En fin de mise en place, un rappel r\u00e9glementaire syst\u00e9matique est effectu\u00e9 pour tout le monde."),
            ("Quel est l\u2019\u00e9l\u00e9ment le plus important du rappel r\u00e9glementaire ?", "La signature de la lettre d\u2019information et du formulaire de consentement, avant tout acte pratiqu\u00e9 dans le cadre du protocole."),
            ("Combien d\u2019exemplaires du consentement faut-il et pour qui ?", "3 exemplaires : un pour le promoteur, un pour l\u2019archivage sur site, un pour le patient. La date de l\u2019inclusion et de la signature sont inscrites dans le dossier source."),
            ("Pourquoi inscrire la participation dans le dossier source du patient ?", "Pour informer les autres m\u00e9decins que ce patient est inclus dans une \u00e9tude."),
            ("Comment anonymise-t-on les donn\u00e9es en recherche clinique ?", "On supprime tout \u00e9l\u00e9ment nominatif des documents susceptibles de sortir du centre et on attribue un code anonyme (n\u00b0 essai + n\u00b0 centre + n\u00b0 ordre d\u2019inclusion). La correspondance code/identit\u00e9 est conserv\u00e9e dans une liste confidentielle."),
            ("Quelles sont les r\u00e8gles de remplissage du CRF papier ?", "Stylo \u00e0 bille noir, lettres capitales, remplir toutes les cases (ND, NF, NA, NC pour les manquantes), reporter le code du participant sur chaque page."),
            ("Comment corriger une donn\u00e9e dans un CRF papier ?", "Rayer d\u2019un simple trait, corriger la donn\u00e9e, dater et parapher par l\u2019investigateur."),
            ("Quelles sont les \u00e9tapes du recueil et traitement des donn\u00e9es ?", "Remplissage r\u00e9gulier des CRF, validation par ARC promoteur, envoi au centre de m\u00e9thodologie et gestion (URC), saisie des donn\u00e9es (data management), exploitation (analyses statistiques)."),
            ("Qu\u2019est-ce qu\u2019un \u00e9v\u00e9nement ind\u00e9sirable grave (EIG) ?", "Tout \u00e9v\u00e9nement qui entra\u00eene la mort, met en danger la vie, n\u00e9cessite une hospitalisation ou prolongation, provoque une incapacit\u00e9 durable, ou se traduit par une anomalie ou malformation cong\u00e9nitale."),
            ("Quels autres cas peuvent \u00eatre consid\u00e9r\u00e9s comme EIG ?", "Un \u00e9v\u00e9nement n\u00e9cessitant une intervention m\u00e9dicale ou chirurgicale pour pr\u00e9venir l\u2019\u00e9volution vers un \u00e9tat grave, ou tout \u00e9v\u00e9nement jug\u00e9 potentiellement grave par l\u2019investigateur ou le promoteur."),
            ("Quand le monitoring a-t-il lieu en cours d\u2019\u00e9tude ?", "Apr\u00e8s la premi\u00e8re inclusion, r\u00e9guli\u00e8rement selon la vitesse d\u2019inclusion, et en fin d\u2019\u00e9tude."),
            ("Pendant combien de temps un audit ou une inspection peut-il avoir lieu apr\u00e8s la cl\u00f4ture ?", "Jusqu\u2019\u00e0 15 ans apr\u00e8s la cl\u00f4ture de l\u2019\u00e9tude."),
            ("Combien de temps les documents doivent-ils \u00eatre archiv\u00e9s apr\u00e8s la fin d\u2019une \u00e9tude ?", "15 ans apr\u00e8s la fin de l\u2019\u00e9tude."),
            ("Quels documents doivent \u00eatre accessibles lors du monitoring ?", "Consentements, CRF, dossiers source, classeur investigateur \u00e0 jour, et tout document concernant les produits \u00e0 l\u2019essai et les \u00e9chantillons."),
            ("Qui doit \u00eatre obligatoirement pr\u00e9sent lors du monitoring ?", "L\u2019investigateur, pour fournir les informations n\u00e9cessaires, r\u00e9pondre aux questions m\u00e9dicales et r\u00e9aliser les corrections dat\u00e9es et paraph\u00e9es."),
            ("Quels documents suppl\u00e9mentaires la pharmacie doit-elle pr\u00e9senter lors du monitoring ?", "Accus\u00e9s de r\u00e9ception des lots, certificats de transport/conservation, certificat d\u2019analyse, ordonnances sp\u00e9cifiques, certificat de distribution, de comptabilit\u00e9, et liste de randomisation le cas \u00e9ch\u00e9ant."),
            ("Quels documents le laboratoire doit-il pr\u00e9senter lors du monitoring ?", "Fiche de tra\u00e7abilit\u00e9 des pr\u00e9l\u00e8vements, ordonnances d\u2019examen, feuilles de r\u00e9sultats d\u2019examen (document source), ordonnances sp\u00e9cifiques au projet."),
            ("Qu\u2019est-ce qu\u2019une modification substantielle du protocole ?", "Une modification touchant l\u2019ouverture de centre, le changement d\u2019investigateur, d\u2019autres examens, d\u2019objectifs, la prolongation de la dur\u00e9e ou le changement de crit\u00e8res d\u2019inclusion."),
            ("Quelles d\u00e9marches sont n\u00e9cessaires pour une modification substantielle ?", "Avertir le promoteur, demander un avis compl\u00e9mentaire aupr\u00e8s des autorit\u00e9s administratives comp\u00e9tentes, et attendre l\u2019avis favorable avant d\u2019appliquer la modification."),
            ("Qu\u2019est-ce que la randomisation d\u00e9s\u00e9quilibr\u00e9e dans l\u2019essai exemple ?", "La r\u00e9partition in\u00e9gale des patients entre les groupes : 24 dans le groupe 1 et 46 dans le groupe 2."),
            ("Qu\u2019est-ce qu\u2019un vaccin conjugu\u00e9 par rapport \u00e0 un vaccin polysaccharidique ?", "Un vaccin conjugu\u00e9 couple les antig\u00e8nes polysaccharidiques \u00e0 une prot\u00e9ine porteuse (anatoxine), transformant les antig\u00e8nes thymo-ind\u00e9pendants en thymo-d\u00e9pendants, ce qui donne une meilleure immunog\u00e9nicit\u00e9 et une r\u00e9ponse m\u00e9moire."),
            ("Qu\u2019est-ce que le sch\u00e9ma \u00ab prime-boost \u00bb dans l\u2019essai vaccinal ?", "Strat\u00e9gie consistant \u00e0 administrer d\u2019abord le vaccin conjugu\u00e9 (PnCj) \u00e0 S0, suivi du vaccin polysaccharidique (PPS) \u00e0 S4, pour am\u00e9liorer la r\u00e9ponse immunitaire."),
            ("Comment pr\u00e9senter une pathologie lors de la mise en place \u00e0 un public mixte ?", "La pr\u00e9sentation doit \u00eatre suffisamment claire pour le personnel non sp\u00e9cialis\u00e9 mais suffisamment courte pour ne pas ennuyer le sp\u00e9cialiste du domaine."),
            ("Qu\u2019est-ce que l\u2019ouverture de centre ?", "C\u2019est le moment o\u00f9 un centre peut commencer \u00e0 inclure des patients, qui intervient apr\u00e8s la r\u00e9union de mise en place."),
            ("Que signifie ND, NF, NA et NC dans le remplissage du CRF ?", "ND = Donn\u00e9e manquante, NF = Non fait, NA = Non applicable, NC = Non connu."),
            ("Quelles sont les 7 visites de l\u2019essai vaccinal DICV ?", "Visite de pr\u00e9-inclusion (S-4), inclusion (S0), visites de suivi \u00e0 S4, S8, S12, \u00e9valuation finale \u00e0 S24, et visite de suivi \u00e0 S48."),
            ("Quel est l\u2019objectif principal de l\u2019essai vaccinal DICV ?", "Comparer la r\u00e9ponse anticorps sp\u00e9cifique \u00e0 S8 chez des sujets DICV entre le vaccin PPS seul (Groupe 1) et une strat\u00e9gie prime-boost PnCj puis PPS (Groupe 2)."),
            ("Quels sont les objectifs secondaires de l\u2019essai vaccinal DICV ?", "Comparer les r\u00e9ponses anticorps 4 semaines apr\u00e8s chaque administration, comparer la tol\u00e9rance des 2 sch\u00e9mas, comparer la persistance \u00e0 S24, et comparer l\u2019incidence des infections invasives \u00e0 pneumocoque."),
            ("Pourquoi ne peut-on pas conclure sur l\u2019efficacit\u00e9 d\u2019un traitement avec les crit\u00e8res secondaires ?", "Les crit\u00e8res secondaires sont indicatifs. Seul le crit\u00e8re d\u2019\u00e9valuation principal permet de conclure \u00e0 l\u2019efficacit\u00e9 d\u2019un traitement."),
            ("Quels sont les crit\u00e8res de non-inclusion de l\u2019essai DICV ?", "D\u00e9ficit en sous-classe d\u2019IgG, d\u00e9ficit s\u00e9lectif en IgA, corticoth\u00e9rapie au long cours, chimioth\u00e9rapie dans les 3 derni\u00e8res ann\u00e9es, vaccination antipneumococcique dans les 5 derni\u00e8res ann\u00e9es, contre-indications aux vaccins."),
            ("Qu\u2019est-ce que le sch\u00e9ma de monitorage ?", "Un document d\u00e9finissant les niveaux de v\u00e9rification des donn\u00e9es et la fr\u00e9quence des visites de monitoring."),
            ("Quel est le circuit des donn\u00e9es dans un essai clinique ?", "Recueil par l\u2019investigateur/TEC dans le CRF \u2192 validation par l\u2019ARC \u2192 envoi \u00e0 l\u2019URC \u2192 saisie (data management) \u2192 analyses statistiques."),
            ("Pourquoi les E-CRF industriels sont-ils plus difficiles d\u2019utilisation ?", "Ils sont d\u00e9velopp\u00e9s par des industriels avec des interfaces plus complexes, contrairement aux logiciels acad\u00e9miques comme CleanWeb qui sont simples d\u2019utilisation."),
            ("Que permet le recueil des donn\u00e9es personnelles du patient dans l\u2019E-CRF ?", "Il permet de retrouver un patient perdu de vue, notamment en se renseignant aupr\u00e8s de la commune de naissance pour savoir si le patient est d\u00e9c\u00e9d\u00e9."),
            ("Qui est le promoteur de l\u2019essai vaccinal DICV pr\u00e9sent\u00e9 en exemple ?", "L\u2019INSERM est le promoteur de cet essai."),
            ("Pourquoi la partie r\u00e9glementaire est-elle importante en recherche clinique ?", "Elle garantit le respect des droits et la s\u00e9curit\u00e9 des patients, la qualit\u00e9 des donn\u00e9es, et la conformit\u00e9 de l\u2019\u00e9tude aux normes l\u00e9gales en vigueur."),
            ("Que doit-on informer au promoteur concernant le consentement ?", "La date de signature du premier consentement de l\u2019\u00e9tude dans le centre."),
            ("Que faut-il inscrire dans le dossier source du patient lors de l\u2019inclusion ?", "La date de l\u2019inclusion et la date de signature du consentement."),
            ("Quels sont les \u00e9l\u00e9ments d\u00e9pos\u00e9s sur ClinicalTrials.gov avant le d\u00e9but de l\u2019essai ?", "Les couleurs, le design, la m\u00e9thodologie, les crit\u00e8res d\u2019inclusion et de non-inclusion, et les crit\u00e8res d\u2019\u00e9valuation de l\u2019\u00e9tude."),
            ("Qu\u2019est-ce que la pharmacie \u00e0 usage int\u00e9rieur (PUI) dans un essai clinique ?", "L\u2019entit\u00e9 qui assure le stockage, la distribution et la gestion des m\u00e9dicaments exp\u00e9rimentaux au sein de l\u2019\u00e9tablissement."),
            ("En quoi la d\u00e9claration sur ClinicalTrials.gov renforce-t-elle la rigueur scientifique ?", "Elle oblige \u00e0 d\u00e9terminer le crit\u00e8re d\u2019\u00e9valuation principal en amont, ce qui emp\u00eache de le modifier au moment des r\u00e9sultats."),
            ("Combien de visites comporte l\u2019essai vaccinal DICV et sur quelle dur\u00e9e ?", "7 visites sur une dur\u00e9e de 48 semaines (S-4 \u00e0 S48)."),
            ("Qu\u2019est-ce que l\u2019hypogammaglobulin\u00e9mie dans le contexte du DICV ?", "C\u2019est une diminution des immunoglobulines (anticorps) dans le sang, caract\u00e9ristique du D\u00e9ficit Immunitaire Commun Variable."),
            ("Quel est le pronostic du DICV ?", "Il est essentiellement li\u00e9 aux infections r\u00e9cidivantes et \u00e0 leurs complications. Les m\u00e9canismes mol\u00e9culaires de la maladie ne sont pas connus."),
            ("Pourquoi le vaccin PPS n\u00e9cessite-t-il un rappel tous les 5 ans ?", "Le vaccin polysaccharidique PPS n\u2019induit pas de r\u00e9ponse m\u00e9moire, d\u2019o\u00f9 la n\u00e9cessit\u00e9 d\u2019injections de rappel p\u00e9riodiques."),
            ("Quels sont les assureurs sp\u00e9cialis\u00e9s dans la recherche clinique ?", "Gerling est un exemple d\u2019assureur sp\u00e9cialis\u00e9 dans la recherche clinique."),
            ("Quelle est la diff\u00e9rence entre la visite de pr\u00e9-inclusion et l\u2019inclusion ?", "La pr\u00e9-inclusion (S-4) sert \u00e0 v\u00e9rifier l\u2019\u00e9ligibilit\u00e9 du patient. L\u2019inclusion (S0) est le moment o\u00f9 le patient est formellement enr\u00f4l\u00e9 dans l\u2019\u00e9tude et re\u00e7oit le premier traitement."),
            ("Quel est le caract\u00e8re de la recherche clinique vis-\u00e0-vis du patient dans le DICV ?", "Les patients DICV sont des mauvais r\u00e9pondeurs au vaccin PPS, ils constituent donc une population potentiellement apte \u00e0 b\u00e9n\u00e9ficier de l\u2019approche vaccinale conjugu\u00e9e."),
            ("Qu\u2019est-ce qu\u2019une demande sp\u00e9cifique d\u2019autorisation aupr\u00e8s de la CNIL ?", "Quand la m\u00e9thodologie de r\u00e9f\u00e9rence ne suffit pas, le promoteur peut faire une demande sp\u00e9cifique pour recueillir des donn\u00e9es sensibles et intimes, avec un certain d\u00e9lai."),
        ]
    },
    {
        "id": "sp_gestion_fc6",
        "filename": "fc6.html",
        "folder": "SP_Gestion",
        "title_h1": "Gestion de projet",
        "title_h2": "Le dossier patient, les CRF et les bases de donn\u00e9es (FC6)",
        "flashcards": [
            ("Qu\u2019est-ce qu\u2019une donn\u00e9e source selon les BPC 1.18 ?", "Ensemble des informations figurant dans des documents originaux relatifs aux examens cliniques, observations ou autres activit\u00e9s d\u2019une recherche biom\u00e9dicale, n\u00e9cessaires \u00e0 la reconstitution et l\u2019\u00e9valuation de la recherche."),
            ("Qu\u2019est-ce qu\u2019un document source selon les BPC 1.17 ?", "Document original, donn\u00e9es et enregistrements pr\u00e9sentant un int\u00e9r\u00eat pour la recherche : dossiers m\u00e9dicaux, fichiers administratifs, comptes rendus de laboratoire, notes de service, agendas, carnets d\u2019auto\u00e9valuation."),
            ("Quel est le but d\u2019un projet de recherche vis-\u00e0-vis des documents sources ?", "Recueillir certains \u00e9l\u00e9ments contenus dans les documents sources, les recopier dans une base de donn\u00e9es afin d\u2019analyser ce qui int\u00e9resse la recherche."),
            ("Qui g\u00e9n\u00e8re les documents sources ?", "Les investigateurs, co-investigateurs, le personnel de sant\u00e9, le sujet participant, et toute autre personne impliqu\u00e9e (pharmacien, biologiste, etc.)."),
            ("Que dit la r\u00e8gle BPC 4.9.2 sur la coh\u00e9rence des donn\u00e9es ?", "Les donn\u00e9es du cahier d\u2019observation provenant des documents sources doivent \u00eatre coh\u00e9rentes avec ceux-ci. Toute diff\u00e9rence doit \u00eatre justifi\u00e9e et document\u00e9e."),
            ("Qu\u2019est-ce que le dossier patient selon le CSP article L1111-14 ?", "Le lieu de recueil et de conservation des informations administratives, m\u00e9dicales et param\u00e9dicales formalis\u00e9es et actualis\u00e9es, cr\u00e9\u00e9 au premier contact du patient avec l\u2019\u00e9tablissement."),
            ("Quand est cr\u00e9\u00e9 le dossier patient ?", "Lors du premier contact du patient avec l\u2019\u00e9tablissement de soins (consultation externe ou hospitalisation). Il s\u2019enrichit ensuite au fil du parcours."),
            ("Quels sont les objectifs du dossier patient ?", "Outil de r\u00e9flexion et synth\u00e8se m\u00e9dicale, aide-m\u00e9moire pour le professionnel, coordination des actions entre professionnels, tra\u00e7abilit\u00e9 m\u00e9dico-l\u00e9gale, recueil d\u2019informations standardis\u00e9es, et \u00e9valuation des pratiques."),
            ("Quels types d\u2019informations trouve-t-on dans le dossier patient ?", "Informations m\u00e9dicales ant\u00e9rieures, informations relatives \u00e0 la personne et habitudes de vie, informations m\u00e9dicales du s\u00e9jour, et informations relatives aux soins param\u00e9dicaux."),
            ("Qu\u2019est-ce que la CIM ?", "La Classification Internationale des Maladies de l\u2019OMS, utilis\u00e9e pour les diagnostics, signes et sympt\u00f4mes."),
            ("Qu\u2019est-ce que la CCAM ?", "La Classification Commune des Actes M\u00e9dicaux pour les actes techniques des m\u00e9decins. Chaque acte a un co\u00fbt d\u00e9fini."),
            ("Depuis quand le codage des actes et pathologies est-il obligatoire ?", "Depuis les ordonnances de 1996 (PMSI \u2013 Programme de M\u00e9dicalisation des Syst\u00e8mes d\u2019Information)."),
            ("Quels \u00e9l\u00e9ments minimaux figurent dans un dossier m\u00e9dical (CSP R1112-2, Partie I) ?", "Lettre du m\u00e9decin d\u2019origine, motifs d\u2019hospitalisation, ant\u00e9c\u00e9dents et facteurs de risque, conclusions cliniques initiales, prescriptions, soins dispens\u00e9s, prise en charge en cours d\u2019hospitalisation, d\u00e9marche m\u00e9dicale, dossier anesth\u00e9sie, compte rendu op\u00e9ratoire."),
            ("Quels \u00e9l\u00e9ments figurent dans la Partie II du dossier m\u00e9dical (\u00e0 la fin du s\u00e9jour) ?", "Compte rendu d\u2019hospitalisation, lettre de sortie, prescription de sortie, modalit\u00e9s de sortie, fiche de liaison infirmi\u00e8re."),
            ("O\u00f9 doivent \u00eatre incluses les donn\u00e9es m\u00e9dicales d\u2019un protocole de recherche ?", "Dans le dossier patient, ainsi que les documents de consentement. Les cahiers d\u2019observation destin\u00e9s au promoteur ne font pas partie du dossier mais doivent \u00eatre archiv\u00e9s."),
            ("Quelle est la dur\u00e9e de conservation du dossier m\u00e9dical ?", "Au moins 20 ans apr\u00e8s le dernier s\u00e9jour/consultation, jusqu\u2019\u00e0 28 ans pour les mineurs, 30 ans pour les dossiers de transfusion, 10 ans apr\u00e8s le d\u00e9c\u00e8s."),
            ("Que se passe-t-il apr\u00e8s expiration du d\u00e9lai de conservation du dossier ?", "Le dossier peut \u00eatre \u00e9limin\u00e9 apr\u00e8s d\u00e9cision du Directeur de l\u2019\u00e9tablissement, avis du m\u00e9decin responsable de l\u2019information m\u00e9dicale, et approbation de l\u2019administration des archives."),
            ("Comment le dossier patient peut-il \u00eatre structur\u00e9 ?", "Par acteurs (m\u00e9dical, infirmier, kin\u00e9, etc.), par type d\u2019information (lettres, comptes rendus, imagerie, etc.) ou de mani\u00e8re temporelle/chronologique."),
            ("Qu\u2019est-ce que le DMP ?", "Le Dossier M\u00e9dical Personnel, un dossier m\u00e9dical informatis\u00e9 accessible via Internet, support d\u2019information d\u00e9mat\u00e9rialis\u00e9 et partag\u00e9, visant \u00e0 am\u00e9liorer la coordination des soins."),
            ("Qui alimente le DMP et qui en autorise l\u2019acc\u00e8s ?", "Les m\u00e9decins alimentent le DMP. Le patient autorise les m\u00e9decins qu\u2019il souhaite \u00e0 y acc\u00e9der."),
            ("Quelles sont les exigences de qualit\u00e9 pour les documents sources ?", "Correctement produits (qualit\u00e9), consign\u00e9s (p\u00e9rennit\u00e9), rapport\u00e9s (qualit\u00e9 de la transcription), archiv\u00e9s (r\u00e9duction du risque de perte), dat\u00e9s et identifi\u00e9s (nom des professionnels)."),
            ("Quel est le r\u00f4le du TEC vis-\u00e0-vis du dossier patient ?", "Le TEC recueille uniquement les informations pertinentes dans le dossier patient et les saisit ensuite dans le CRF."),
            ("Qu\u2019est-ce que le CRF (Case Report Form) ?", "Le cahier d\u2019observation, document sp\u00e9cifique \u00e0 la recherche destin\u00e9 \u00e0 recueillir toutes les informations requises par le protocole, devant \u00eatre transmises au promoteur."),
            ("Qui v\u00e9rifie la coh\u00e9rence entre le dossier patient et le CRF ?", "L\u2019attach\u00e9 de recherche clinique (ARC) v\u00e9rifie cette coh\u00e9rence."),
            ("Que sont les donn\u00e9es de soin devenues donn\u00e9es sources ?", "Parfois des items n\u00e9cessaires \u00e0 la recherche deviennent des donn\u00e9es sources : elles sont class\u00e9es dans le dossier m\u00e9dical et constituent \u00e0 la fois des donn\u00e9es de soin et des donn\u00e9es sources."),
            ("Quels sont les r\u00f4les et devoirs de l\u2019investigateur ?", "Respect des BPC, recueil du consentement, d\u00e9claration des EIG, d\u00e9claration des arr\u00eats pr\u00e9matur\u00e9s, remplissage du cahier d\u2019observation, mise \u00e0 jour du dossier source."),
            ("Qu\u2019est-ce que le monitoring des donn\u00e9es sources ?", "V\u00e9rification par un ARC moniteur mandat\u00e9 par le promoteur, soumis au secret professionnel, ayant un acc\u00e8s direct aux documents sources apr\u00e8s consentement du patient."),
            ("Quels sont les objectifs du monitoring des donn\u00e9es sources ?", "V\u00e9rifier l\u2019existence des patients, la coh\u00e9rence des donn\u00e9es, l\u2019int\u00e9grit\u00e9 et p\u00e9rennit\u00e9 des donn\u00e9es, la qualit\u00e9 des documents sources, l\u2019authenticit\u00e9 et l\u2019exhaustivit\u00e9."),
            ("Comment corriger une d\u00e9viation constat\u00e9e lors du monitoring ?", "La d\u00e9viation est notifi\u00e9e dans le compte rendu de monitoring. La correction doit \u00eatre dat\u00e9e et paraph\u00e9e par l\u2019investigateur ou le TEC sans masquer la donn\u00e9e initiale."),
            ("Quelle est la diff\u00e9rence entre CRF papier et CRF \u00e9lectronique en termes d\u2019\u00e9laboration ?", "Le CRF papier est plus facile \u00e0 mettre en \u0153uvre (base Access/Excel). Le CRF \u00e9lectronique est plus complexe \u00e0 \u00e9laborer mais offre des contr\u00f4les automatis\u00e9s, un suivi des inclusions et la randomisation int\u00e9gr\u00e9e."),
            ("Quelles sont les \u00e9tapes du CRF papier ?", "Liste des items valid\u00e9s, \u00e9laboration, test remplissage, impression, remplissage, \u00e9laboration BDD, tests de saisie, saisie, gel de base."),
            ("Quelles sont les \u00e9tapes du CRF \u00e9lectronique ?", "Liste des items valid\u00e9s, programmation, test, mise en production, remplissage, gel de base."),
            ("Qui participe \u00e0 la pr\u00e9paration du CRF ?", "L\u2019investigateur, le statisticien, le CEC (Centre d\u2019\u00c9valuation Clinique), l\u2019ARC et le Data Manager."),
            ("Quand doit-on commencer la pr\u00e9paration du CRF ?", "D\u00e8s la finalisation du protocole."),
            ("Quelles sont les r\u00e8gles absolues du CRF ?", "Fid\u00e8le au protocole, crit\u00e8res d\u2019inclusion/non-inclusion identiques au protocole au d\u00e9but, bandeau d\u2019identification sur chaque page, crit\u00e8res de jugement clairement formul\u00e9s, fiche EIG obligatoire."),
            ("Que doit contenir le \u00ab bandeau \u00bb de chaque page du CRF ?", "L\u2019identification du patient, le nom du promoteur, le nom de l\u2019\u00e9tude et le nom ou num\u00e9ro de la visite."),
            ("Quelles r\u00e8gles de formulation des questions du CRF faut-il respecter ?", "Questions claires et pr\u00e9cises, \u00e9viter les abr\u00e9viations et sigles, \u00e9viter les questions n\u00e9gatives, pr\u00e9voir des cases r\u00e9ponses avec un seul caract\u00e8re par case, \u00e9viter les items \u00e0 rayer/entourer."),
            ("Que doit contenir la couverture d\u2019un CRF papier ?", "Titre complet et titre court de l\u2019\u00e9tude, code promoteur, identifiant patient et centre, correspondants de l\u2019\u00e9tude, investigateur principal, coordinateurs, chef de projet du promoteur."),
            ("Quel est le plan g\u00e9n\u00e9ral d\u2019un CRF ?", "I. Identification patient, II. Crit\u00e8res d\u2019\u00e9ligibilit\u00e9/inclusion/randomisation, III. Donn\u00e9es du protocole (description population, crit\u00e8res principal et secondaires), IV. Fin d\u2019\u00e9tude, V. \u00c9v\u00e9nements ind\u00e9sirables, VI. EIG."),
            ("Quelles informations doivent figurer sur chaque page d\u2019un CRF papier ?", "Num\u00e9ro de page, identifiant patient, identifiant du centre, espace pour le paraphe de l\u2019investigateur."),
            ("Pourquoi utilise-t-on du papier carbone pour le CRF papier ?", "Pour obtenir des copies automatis\u00e9es : le CRF papier est dupliqu\u00e9, et le formulaire de consentement est tripliqu\u00e9."),
            ("Qu\u2019est-ce que le flow chart dans le contexte du CRF ?", "Un tableau chronologique o\u00f9 1 colonne = 1 visite, permettant de se situer dans le d\u00e9roulement de l\u2019\u00e9tude et de conna\u00eetre les actes \u00e0 r\u00e9aliser."),
            ("Quelles \u00e9tapes suit-on apr\u00e8s la construction du CRF papier ?", "Regrouper les donn\u00e9es par type/th\u00e8me, mise en forme et codage, relecture par l\u2019\u00e9quipe, validation, test de remplissage (patient fictif), validation d\u00e9finitive, impression."),
            ("Quels types de donn\u00e9es peut-on recueillir dans un CRF ?", "Choix multiples, cases \u00e0 cocher (oui/non pr\u00e9f\u00e9r\u00e9), champ texte (difficilement exploitable sans recodage, chronophage mais incontournable pour les EI/EIG)."),
            ("Pourquoi faut-il un guide de remplissage du CRF ?", "Pour standardiser la saisie, \u00e9viter les erreurs d\u2019interpr\u00e9tation, et assurer la qualit\u00e9 et l\u2019homog\u00e9n\u00e9it\u00e9 des donn\u00e9es recueillies."),
            ("Comment doit-on remplir un CRF papier ?", "Stylo \u00e0 bille noir, donn\u00e9es lisibles, correction en barrant, datant et signant."),
            ("Qu\u2019est-ce que le tableau des traitements concomitants ?", "Un tableau tr\u00e8s d\u00e9licat \u00e0 remplir qui recense tous les traitements pris par le patient en dehors de la recherche."),
            ("Qu\u2019est-ce qu\u2019une base de donn\u00e9es informatique (BDD) ?", "Ensemble structur\u00e9 et organis\u00e9 permettant le stockage de grandes quantit\u00e9s d\u2019informations afin d\u2019en faciliter l\u2019exploitation."),
            ("Quelle est la diff\u00e9rence entre une BDD locale et une BDD en ligne ?", "BDD locale : mise \u00e0 jour uniquement sur le poste de l\u2019op\u00e9rateur. BDD en ligne : mise \u00e0 jour en temps r\u00e9el via internet avec protocole s\u00e9curis\u00e9 (cryptage, codes d\u2019acc\u00e8s)."),
            ("Qu\u2019est-ce que le Data Management ?", "L\u2019ensemble des processus permettant la production d\u2019une base de donn\u00e9es fiable, coh\u00e9rente et exploitable par les statisticiens pour r\u00e9pondre aux objectifs de l\u2019\u00e9tude."),
            ("Qu\u2019est-ce qu\u2019un CRF annot\u00e9 ?", "Document renseign\u00e9 par l\u2019ARC indiquant les consignes pour le Data Manager : format des donn\u00e9es, contr\u00f4les, valeurs aberrantes, bornes, contraintes, messages."),
            ("Qu\u2019est-ce qu\u2019un dictionnaire de donn\u00e9es ?", "Premi\u00e8re \u00e9tape de la conception du masque de saisie, d\u00e9finissant les variables de l\u2019\u00e9tude : table, nom, type, format, unit\u00e9, libell\u00e9, liste de codes, cl\u00e9s."),
            ("Quelles sont les \u00e9tapes de cr\u00e9ation d\u2019une base de donn\u00e9es ?", "A. Annotation du CRF, B. Dictionnaire des donn\u00e9es, C. Cr\u00e9ation des tables, D. Sch\u00e9ma relationnel, E. Cr\u00e9ation du masque de saisie, F. Contr\u00f4les de coh\u00e9rence, G. Convention de saisie, H. Test de la base."),
            ("En quoi consiste l\u2019annotation du CRF ?", "Fractionner le CRF en groupes de donn\u00e9es (tables) et annoter le CRF vierge avec les variables et codes."),
            ("Que contient un dictionnaire de donn\u00e9es pour chaque item ?", "Son codage informatique, son nom informatique, la table, le type (texte, date, entier, r\u00e9el), le format (taille, d\u00e9cimale), l\u2019unit\u00e9, le libell\u00e9, la liste de codes et les cl\u00e9s (primaire, \u00e9trang\u00e8re)."),
            ("Qu\u2019est-ce qu\u2019un masque de saisie ?", "Interface utilisateur comportant des zones de saisie (texte, radio-boutons, combo-box, cases \u00e0 cocher, listes, boutons) permettant l\u2019interaction avec la base de donn\u00e9es, fid\u00e8le au CRF papier."),
            ("Qu\u2019est-ce qu\u2019un contr\u00f4le de coh\u00e9rence ?", "Des contraintes entre variables : par exemple, ne pas poser de questions sur la grossesse pour un homme, ou proposer des questions sur la m\u00e9nopause pour une femme."),
            ("Comment teste-t-on une base de donn\u00e9es avant mise en production ?", "Saisie de patients fictifs, v\u00e9rification masque vs CRF papier, test de convivialit\u00e9 et ergonomie, v\u00e9rification des champs, extraction et v\u00e9rification des enregistrements et requ\u00eates d\u2019export."),
            ("Comment code-t-on les donn\u00e9es manquantes ou illisibles ?", "97, 98, 99, ND (non disponible), DCF (data clarification form), NA (non applicable)."),
            ("Quels sont les types de saisie possibles pour une BDD ?", "Saisie simple, double saisie ind\u00e9pendante (confrontation des bases), double saisie interactive (alerte si discordance), import de donn\u00e9es externes."),
            ("Qu\u2019est-ce que l\u2019Audit Trail ?", "Le suivi des saisies et modifications : qui (utilisateur), quand (date), quoi (variable concern\u00e9e), ancienne valeur et nouvelle valeur."),
            ("Quelles sont les r\u00e8gles de saisie des donn\u00e9es du CRF ?", "Saisir les donn\u00e9es sans les interpr\u00e9ter, ne pas revenir sur ce qui a \u00e9t\u00e9 saisi sauf si POS de correction ou demande du data manager."),
            ("Comment assure-t-on la sauvegarde de la base de donn\u00e9es ?", "Par des copies fr\u00e9quentes, des sauvegardes r\u00e9guli\u00e8res et l\u2019archivage des anciennes versions."),
            ("Qu\u2019est-ce que le CRF \u00e9lectronique apporte de plus que le CRF papier ?", "Gestion des utilisateurs et profils, mise en ligne de documents, mails d\u2019information automatiques, gestion des unit\u00e9s de traitement, Audit Trail int\u00e9gr\u00e9, extraction, statistiques, contr\u00f4les de coh\u00e9rence, monitoring."),
            ("Que permet le tableau de bord d\u2019un E-CRF ?", "Il donne une synth\u00e8se sur le nombre d\u2019inclusions par service, par m\u00e9decin, par centre, et la courbe d\u2019inclusion."),
            ("Comment acc\u00e8de-t-on \u00e0 un E-CRF ?", "Par un acc\u00e8s nominatif, personnel et secret via une adresse internet s\u00e9curis\u00e9e."),
            ("Qui remplit g\u00e9n\u00e9ralement le CRF \u00e9lectronique ?", "Le TEC (Technicien d\u2019\u00c9tude Clinique) le plus souvent."),
            ("Qu\u2019est-ce qu\u2019une query ?", "Une requ\u00eate ou demande d\u2019information \u00e9mise par le Data Manager ou l\u2019ARC concernant des donn\u00e9es manquantes ou incoh\u00e9rentes dans le CRF."),
            ("Quels sont les statuts possibles d\u2019une query ?", "Ouvert, r\u00e9solu, confirm\u00e9, non v\u00e9rifiable."),
            ("Quand ex\u00e9cute-t-on les contr\u00f4les et \u00e9missions de queries ?", "R\u00e9guli\u00e8rement tant que la saisie n\u2019est pas termin\u00e9e et tant qu\u2019il reste des queries ouvertes."),
            ("Quand la base de donn\u00e9es est-elle gel\u00e9e ?", "Quand tous les CRF sont saisis, toutes les corrections int\u00e9gr\u00e9es, monitoring termin\u00e9, contr\u00f4les sans anomalies, codification valid\u00e9e, contr\u00f4le qualit\u00e9 effectu\u00e9, consolidation avec la PV, r\u00e9union de Blind-Review r\u00e9alis\u00e9e, plan d\u2019analyse valid\u00e9."),
            ("Qui verrouille la base de donn\u00e9es et que se passe-t-il ensuite ?", "Le Data Manager effectue le verrouillage informatique. Les donn\u00e9es ne sont plus modifiables (lecture seule) et les fichiers sont transf\u00e9r\u00e9s au statisticien pour analyse."),
            ("Sous quels formats les fichiers de la base gel\u00e9e sont-ils export\u00e9s ?", "SAS, Excel, CSV, prot\u00e9g\u00e9s par un mot de passe."),
            ("Qu\u2019est-ce que la r\u00e9union de Blind-Review ?", "Une r\u00e9union r\u00e9alis\u00e9e avant le gel de base pour revoir les donn\u00e9es en aveugle et valider le plan d\u2019analyse statistique."),
            ("Pourquoi le champ texte est-il probl\u00e9matique dans un CRF ?", "Il est difficilement exploitable sans recodage, tr\u00e8s chronophage, mais incontournable pour la description des \u00e9v\u00e9nements ind\u00e9sirables (EI/EIG)."),
            ("Qu\u2019est-ce que la consolidation avec la PV avant le gel de base ?", "La v\u00e9rification conjointe avec la Pharmacovigilance pour s\u2019assurer que tous les \u00e9v\u00e9nements ind\u00e9sirables ont \u00e9t\u00e9 correctement d\u00e9clar\u00e9s et document\u00e9s."),
            ("Que signifie DCF dans le codage des donn\u00e9es ?", "Data Clarification Form : formulaire utilis\u00e9 pour demander des \u00e9claircissements sur des donn\u00e9es manquantes ou incoh\u00e9rentes."),
            ("Quel est le r\u00f4le du sch\u00e9ma relationnel dans la BDD ?", "Il d\u00e9finit les relations entre les diff\u00e9rentes tables de la base de donn\u00e9es, assurant la coh\u00e9rence structurelle des informations."),
            ("Comment le principe du secret professionnel s\u2019applique-t-il au dossier patient ?", "Le partage est limit\u00e9 aux personnels ayant particip\u00e9 aux soins. La communication pour enseignement ou recherche \u00e0 un m\u00e9decin non impliqu\u00e9 n\u00e9cessite l\u2019accord du patient ou des donn\u00e9es anonymes."),
            ("Suffit-il d\u2019occulter le nom et pr\u00e9nom pour anonymiser les donn\u00e9es ?", "Non. Toute combinaison permettant d\u2019identifier le patient est consid\u00e9r\u00e9e comme nominative, y compris les listes de correspondance num\u00e9ro/identit\u00e9."),
            ("Qu\u2019est-ce que le PMSI ?", "Le Programme de M\u00e9dicalisation des Syst\u00e8mes d\u2019Information, qui a rendu obligatoire le codage des actes et pathologies depuis 1996."),
            ("Quels sont les avantages de la gestion des unit\u00e9s de traitement dans un E-CRF ?", "Approvisionnement, alerte stock, gestion de la p\u00e9remption des m\u00e9dicaments, tra\u00e7abilit\u00e9 automatis\u00e9e."),
        ]
    },
    {
        "id": "sp_gestion_fc7",
        "filename": "fc7.html",
        "folder": "SP_Gestion",
        "title_h1": "Gestion de projet",
        "title_h2": "Le monitoring (FC7)",
        "flashcards": [
            ("Qu\u2019est-ce qu\u2019un ARC moniteur ?", "Un Attach\u00e9 de Recherche Clinique mandat\u00e9 par le promoteur, charg\u00e9 d\u2019assurer le suivi de la recherche biom\u00e9dicale et le contr\u00f4le de sa qualit\u00e9 (BPC 1.37)."),
            ("Quelle est la d\u00e9finition du monitoring (BPC 1.48) ?", "Activit\u00e9 consistant \u00e0 surveiller le d\u00e9roulement d\u2019une recherche et \u00e0 s\u2019assurer qu\u2019elle est conduite et que les donn\u00e9es sont recueillies conform\u00e9ment au protocole, aux BPC et aux dispositions l\u00e9gislatives en vigueur."),
            ("Quelles sont les six missions principales de l\u2019ARC moniteur (BPC 5.18.4) ?", "a) Liaison promoteur-investigateur\nb) V\u00e9rification des fonctions de l\u2019\u00e9quipe\nc) V\u00e9rification du recrutement\nd) V\u00e9rification de l\u2019exactitude des donn\u00e9es\ne) Suivi des EI\nf) D\u00e9tection et r\u00e9solution des difficult\u00e9s."),
            ("Quels sont les trois objectifs du monitoring (BPC 5.18.1) ?", "a) V\u00e9rifier les droits, la s\u00e9curit\u00e9 et la protection des personnes\nb) V\u00e9rifier que les donn\u00e9es sont exactes, compl\u00e8tes et coh\u00e9rentes avec les documents sources\nc) V\u00e9rifier la conformit\u00e9 au protocole et aux BPC."),
            ("Qu\u2019est-ce que le promoteur dans un essai clinique ?", "L\u2019entit\u00e9 responsable de la recherche en termes juridiques : assure la s\u00e9curit\u00e9 du patient, l\u2019aspect financier, et v\u00e9rifie que tous les actes sont financ\u00e9s."),
            ("Quel est le r\u00f4le du chef de projet ?", "C\u2019est le coordinateur/r\u00e9f\u00e9rent des ARC : il valide les actes des ARC, assure l\u2019obtention des autorisations r\u00e9glementaires, construit le protocole."),
            ("Quel est le r\u00f4le de l\u2019investigateur sur site ?", "Le m\u00e9decin sur site qui traite les patients avec l\u2019acte exp\u00e9rimental, assist\u00e9 du TEC."),
            ("Qu\u2019est-ce que la PUI dans le contexte du monitoring ?", "La Pharmacie \u00e0 Usage Int\u00e9rieur, qui dispense les traitements m\u00e9dicamenteux pour les essais cliniques."),
            ("Pourquoi le monitoring doit-il d\u00e9tecter les erreurs pr\u00e9cocement ?", "Pour \u00e9viter leur r\u00e9apparition et garantir la qualit\u00e9 des donn\u00e9es d\u00e8s le d\u00e9but de l\u2019\u00e9tude."),
            ("Qu\u2019est-ce que le plan de monitoring ?", "Un document construit avant le d\u00e9but de l\u2019\u00e9tude, d\u00e9finissant les r\u00e8gles de monitoring adapt\u00e9es \u00e0 la qualification, la complexit\u00e9 et les risques de l\u2019\u00e9tude."),
            ("Quelles sont les \u00e9tapes de la m\u00e9thode Optimon pour \u00e9laborer le plan de monitoring ?", "1) D\u00e9finir le niveau de risque patient (cat\u00e9goriser l\u2019essai)\n2) Calculer le score LIR (1 \u00e0 40)\n3) D\u00e9finir le niveau de monitoring (minimal, interm\u00e9diaire, \u00e9lev\u00e9)\n4) \u00c9laborer le plan sp\u00e9cifique."),
            ("Qu\u2019est-ce que le score LIR ?", "Le score Logistique et Impact Ressources (de 1 \u00e0 40), qui d\u00e9termine le degr\u00e9 de complexit\u00e9 et de comp\u00e9tence n\u00e9cessaire pour l\u2019essai."),
            ("Que signifie un score LIR \u2265 20 ?", "La recherche est complexe, le niveau de monitoring est interm\u00e9diaire \u00e0 \u00e9lev\u00e9."),
            ("Que signifie un score LIR < 20 ?", "Le monitoring est ultra-light (minimal)."),
            ("Quelles donn\u00e9es sont \u00e0 monitorer au minimum pour un niveau \u00e9lev\u00e9 ?", "Les consentements, les crit\u00e8res de s\u00e9lection, les \u00e9v\u00e9nements ind\u00e9sirables et les crit\u00e8res d\u2019\u00e9valuation principaux."),
            ("Qu\u2019est-ce qu\u2019un SUSAR ?", "Suspected Unexpected Serious Adverse Reaction : suspicion d\u2019effet ind\u00e9sirable grave inattendu, qui doit \u00eatre d\u00e9tect\u00e9e lors du monitoring."),
            ("Le plan de monitoring peut-il \u00eatre modifi\u00e9 en cours de recherche ?", "Oui, le plan de monitoring peut \u00eatre modifi\u00e9 au cours de la recherche si n\u00e9cessaire."),
            ("Comment l\u2019ARC organise-t-il le rendez-vous de monitoring ?", "Par mail, en proposant plusieurs dates dans un d\u00e9lai raisonnable (1 mois avant), avec confirmation incluant date, heure, objectifs, dur\u00e9e, personnes \u00e0 rencontrer, documents \u00e0 pr\u00e9parer, et rappel \u00e0 J-2."),
            ("Quels documents de r\u00e9f\u00e9rence l\u2019ARC emporte-t-il pour la visite ?", "BPC, Dorosz, RCP des m\u00e9dicaments."),
            ("Quels outils pratiques l\u2019ARC utilise-t-il lors du monitoring ?", "Post-it (interdit d\u2019\u00e9crire sur les dossiers m\u00e9dicaux), petit mat\u00e9riel (agrafeuse, marqueur, ruban adh\u00e9sif, pochettes, calculatrice), PC portable, cl\u00e9 USB."),
            ("Quels documents l\u2019ARC emporte-t-il pour la mise \u00e0 jour du classeur investigateur ?", "Protocole et NIFC en vigueur, avis et autorisations, formulaire de d\u00e9l\u00e9gation de fonctions, engagements de responsabilit\u00e9, CV des investigateurs, calendrier des visites, liste des patients mise \u00e0 jour."),
            ("Que fait l\u2019ARC en arrivant sur site ?", "Il informe de son arriv\u00e9e, se pr\u00e9sente \u00e0 l\u2019investigateur et au TEC, rappelle l\u2019organisation de la visite, et s\u2019assure de la disponibilit\u00e9 des \u00e9l\u00e9ments demand\u00e9s."),
            ("Quels sont les contr\u00f4les effectu\u00e9s pendant le monitoring (BPC 5.18.4) ?", "Existence du patient, signatures/dates des consentements, crit\u00e8res d\u2019inclusion/non-inclusion/\u00e9valuation, respect du protocole, EI, qualit\u00e9 des donn\u00e9es, gestion des traitements, services m\u00e9dico-techniques."),
            ("Quelle est la premi\u00e8re chose \u00e0 v\u00e9rifier lors d\u2019un monitoring ?", "Le consentement \u00e9clair\u00e9 : il doit \u00eatre sign\u00e9 et dat\u00e9 ant\u00e9rieurement \u00e0 tout acte de la recherche (BPC 5.18.4)."),
            ("Qui a le droit de signer un consentement en tant qu\u2019investigateur ?", "Un m\u00e9decin th\u00e9s\u00e9, inscrit \u00e0 l\u2019Ordre des m\u00e9decins, avec un num\u00e9ro RPPS, et ayant sign\u00e9 le formulaire de d\u00e9l\u00e9gation de fonctions."),
            ("Combien d\u2019exemplaires du consentement et pour qui ?", "3 exemplaires : l\u2019original pour l\u2019investigateur (dans le classeur investigateur), une copie pour le patient, une copie sous enveloppe scell\u00e9e pour le promoteur."),
            ("Peut-on ouvrir le dossier source sans consentement ?", "Non, il ne faut pas ouvrir le dossier source en l\u2019absence de consentement (BPC 5.18.4)."),
            ("Quel est le taux de non-conformit\u00e9 des consentements ?", "Dans 95% des cas, le consentement est faux ou mal fait car il manque une ou des informations."),
            ("Que faut-il en plus de la signature du consentement ?", "Une notification dans le dossier m\u00e9dical du patient expliquant qu\u2019il a \u00e9t\u00e9 inclus, inform\u00e9 et a consenti. C\u2019est souvent oubli\u00e9 par les m\u00e9decins."),
            ("Que v\u00e9rifie-t-on lors du monitoring des donn\u00e9es recueillies ?", "V\u00e9racit\u00e9 (CRF vs dossier source), tra\u00e7abilit\u00e9, coh\u00e9rence, randomisation, compl\u00e9tude, et identification des erreurs de transcription, donn\u00e9es illisibles, manquantes, EIG non notifi\u00e9s."),
            ("Quelles donn\u00e9es doit-on monitorer au minimum ?", "Les crit\u00e8res d\u2019\u00e9ligibilit\u00e9, les crit\u00e8res d\u2019\u00e9valuation, et les variables essentielles \u00e0 l\u2019analyse d\u00e9termin\u00e9es par le statisticien."),
            ("Comment corrige-t-on les donn\u00e9es sur le CRF papier lors du monitoring ?", "Faire barrer, dater, signer et parapher par l\u2019investigateur. Utiliser un stylo \u00e0 bille noir, donn\u00e9es lisibles."),
            ("Que v\u00e9rifie-t-on lors du monitoring de la pharmacie ?", "R\u00e9ception, r\u00e9approvisionnement, dispensation des UT (respect randomisation, posologie, aveugle), gestion (stockage, p\u00e9remption, comptabilit\u00e9, retour, destruction), mise \u00e0 jour du classeur pharmacie, CV et FDF."),
            ("Que signifie UT dans le contexte du monitoring ?", "Unit\u00e9 de Traitement : le m\u00e9dicament exp\u00e9rimental sous ses diff\u00e9rentes formes."),
            ("Que v\u00e9rifie-t-on lors du monitoring des services m\u00e9dico-techniques ?", "Respect du protocole, tra\u00e7abilit\u00e9 conforme, comptabilit\u00e9 des actes et tubes, monitoring des collections biologiques, conditions de stockage, validit\u00e9 du stock de mat\u00e9riel."),
            ("Que fait l\u2019ARC en fin de visite de monitoring ?", "Bilan avec l\u2019\u00e9quipe investigateur, pr\u00e9vision de la prochaine visite, signature du calendrier des visites, rangement et signalement du d\u00e9part."),
            ("Que fait l\u2019ARC apr\u00e8s la visite de retour \u00e0 l\u2019URC ?", "R\u00e9daction du rapport de monitoring, mise \u00e0 jour des tableaux de suivi (inclusions, sorties, d\u00e9c\u00e8s, PDV), mise \u00e0 jour des utilisateurs E-CRF, suivi des EI, \u00e9tat de frais."),
            ("Que contient un rapport de monitoring ?", "Informations de la recherche, date de visite, probl\u00e8mes non r\u00e9solus, \u00e9tat d\u2019avancement du centre, conformit\u00e9 du centre, respect des crit\u00e8res, existence des patients, conformit\u00e9 des consentements, respect du protocole."),
            ("Comment doit-on r\u00e9pondre aux items du rapport de monitoring ?", "Par oui ou non. Chaque \u00ab non \u00bb doit \u00eatre justifi\u00e9 en expliquant la raison de la faute."),
            ("Qu\u2019est-ce que la compliance du patient ?", "Le fait de savoir si le patient a bien pris tous ses m\u00e9dicaments \u00e0 la bonne posologie et au bon moment de prise."),
            ("Quels sont les outils de suivi qui aident au monitoring ?", "Tableaux de suivi des inclusions, des consentements, de l\u2019avancement du monitoring/validation CRF, du suivi des EIG et de la gestion des UT."),
            ("Quand intervient la visite de cl\u00f4ture ?", "Quand les inclusions et le suivi sont termin\u00e9s conform\u00e9ment au protocole, ou de fa\u00e7on pr\u00e9matur\u00e9e sur d\u00e9cision du promoteur."),
            ("Quelles sont les raisons d\u2019une fin pr\u00e9matur\u00e9e du fait du centre ?", "Absence d\u2019inclusion (centre non actif, cl\u00f4ture par courrier possible) ou non-respect du protocole/BPC."),
            ("Quelles sont les raisons d\u2019une fin pr\u00e9matur\u00e9e du fait du promoteur ?", "Un EIG ou une analyse interm\u00e9diaire montrant l\u2019efficacit\u00e9 ou l\u2019inefficacit\u00e9 du traitement."),
            ("Quels sont les objectifs de la visite de cl\u00f4ture ?", "S\u2019assurer de l\u2019archivage des documents, r\u00e9cup\u00e9rer le mat\u00e9riel restant, discuter des suites (audit/inspection possibles)."),
            ("Que fait l\u2019ARC dans le service clinique lors de la cl\u00f4ture ?", "V\u00e9rification des derni\u00e8res donn\u00e9es et queries, v\u00e9rification du classeur investigateur, v\u00e9rification de l\u2019archivage, destruction des documents vierges inutiles."),
            ("Que r\u00e9cup\u00e8re l\u2019ARC pour le promoteur lors de la cl\u00f4ture ?", "Consentements dans des enveloppes inviolables, enveloppes de lev\u00e9e d\u2019insu, feuille de d\u00e9l\u00e9gation de fonctions, fiche de visite de monitoring."),
            ("Que fait l\u2019ARC \u00e0 la pharmacie lors de la cl\u00f4ture ?", "R\u00e9cup\u00e9rer copies des feuilles de comptabilit\u00e9 et certificats de destruction, planifier le retour ou la destruction des UT restantes, archiver les documents."),
            ("Quels rappels l\u2019ARC fait-il \u00e0 l\u2019investigateur lors de la cl\u00f4ture ?", "Confidentialit\u00e9 des donn\u00e9es jusqu\u2019au rapport final, possibilit\u00e9 d\u2019audit ou inspection, r\u00e9ception du courrier de fermeture apr\u00e8s gel de base."),
            ("Que fait l\u2019ARC de retour \u00e0 l\u2019URC apr\u00e8s la cl\u00f4ture ?", "Archiver les documents, r\u00e9diger le rapport de cl\u00f4ture, envoyer des courriers \u00e0 l\u2019investigateur principal, aux directions hospitali\u00e8res, aux pharmacies locales et aux plateaux techniques."),
            ("Qu\u2019est-ce qu\u2019un cas pratique de non-conformit\u00e9 critique ?", "Patient d\u00e9c\u00e9d\u00e9 sans signature du consentement, ou absence de consentement sign\u00e9 ant\u00e9rieur aux actes de recherche. Les donn\u00e9es du patient sont alors inexploitables."),
            ("Que faire si un consentement est absent du classeur investigateur ?", "V\u00e9rifier s\u2019il est dans le dossier m\u00e9dical, le faire ranger dans le classeur investigateur, et si non sign\u00e9, faire signer le patient avec une attestation dat\u00e9e."),
            ("Que faire en cas de consentement sans date de signature ?", "C\u2019est une non-conformit\u00e9 majeure. L\u2019investigateur doit faire signer le formulaire \u00e0 jour \u00e0 la date du jour avec attestation du patient."),
            ("Comment g\u00e8re-t-on le consentement en situation d\u2019urgence vitale ?", "Si le patient est inconscient, faire signer la famille ou personne de confiance. En l\u2019absence de proches, le m\u00e9decin note dans le dossier. D\u00e8s que le patient peut consentir, il signe le formulaire de poursuite."),
            ("Que faire si le dossier source est \u00e9lectronique ?", "L\u2019ARC doit avoir un code d\u2019acc\u00e8s au dossier informatis\u00e9. Si impossible, l\u2019investigateur fournit une impression papier dat\u00e9e et sign\u00e9e."),
            ("Quelle est la dur\u00e9e de conservation des documents selon le type de projet ?", "Elle varie selon le type de projet. La dur\u00e9e peut aller jusqu\u2019\u00e0 15 ans ou plus selon la r\u00e9glementation applicable."),
            ("Qu\u2019est-ce que le RPPS ?", "Le R\u00e9pertoire Partag\u00e9 des Professionnels de Sant\u00e9, n\u00e9cessaire pour qu\u2019un m\u00e9decin puisse signer un consentement en tant qu\u2019investigateur."),
            ("Que v\u00e9rifie-t-on au niveau du classeur investigateur lors du monitoring ?", "Utiliser le sommaire comme check-list, s\u2019assurer que seules les derni\u00e8res versions sont pr\u00e9sentes, classer les documents obsol\u00e8tes dans un classeur archives."),
            ("Quels sont les points \u00e0 v\u00e9rifier concernant le respect du protocole ?", "Crit\u00e8res d\u2019inclusion et non-inclusion, crit\u00e8res d\u2019\u00e9valuation (principal et secondaires), sch\u00e9mas th\u00e9rapeutiques, randomisation, respect des visites."),
            ("\u00c0 retenir : quels sont les six objectifs fondamentaux de l\u2019ARC et du monitoring ?", "Garantir la s\u00e9curit\u00e9 et les droits du patient, garantir la qualit\u00e9 des donn\u00e9es, garantir la qualit\u00e9 du suivi, faire appliquer la r\u00e9glementation et le protocole, transmettre et suivre les probl\u00e8mes, assurer l\u2019archivage."),
            ("Pourquoi l\u2019utilisation des mails est-elle importante dans l\u2019organisation du monitoring ?", "Elle permet de laisser une tra\u00e7abilit\u00e9 de toutes les communications et d\u00e9cisions prises."),
            ("Qu\u2019est-ce qu\u2019une lev\u00e9e d\u2019insu ?", "La r\u00e9v\u00e9lation du traitement re\u00e7u par un patient dans un essai en aveugle, document\u00e9e dans des enveloppes r\u00e9cup\u00e9r\u00e9es lors de la cl\u00f4ture."),
            ("Que signifie PDV dans les tableaux de suivi ?", "Perdu De Vue : un patient qui ne se pr\u00e9sente plus aux visites et dont on a perdu le contact."),
            ("Qu\u2019est-ce que le FDF dans le contexte du monitoring ?", "Le Formulaire de D\u00e9l\u00e9gation de Fonctions, qui liste les personnes autoris\u00e9es \u00e0 effectuer certaines t\u00e2ches dans l\u2019essai."),
            ("Qu\u2019est-ce que le NIFC ?", "La Note d\u2019Information et Formulaire de Consentement, document remis au patient pour l\u2019informer et recueillir son accord."),
            ("Pourquoi l\u2019ARC ne doit-il pas \u00e9crire sur les dossiers m\u00e9dicaux ?", "Les dossiers m\u00e9dicaux sont des documents sources qui ne doivent pas \u00eatre alt\u00e9r\u00e9s. L\u2019ARC utilise des post-it pour annoter ses observations."),
            ("Qu\u2019est-ce que la chronologie d\u2019une recherche clinique ?", "Id\u00e9e et documentation scientifique \u2192 obtention des autorisations (CPP, ANSM, CNIL) \u2192 mise en place \u2192 inclusions et suivi \u2192 monitoring \u2192 gel de base \u2192 analyses."),
            ("Qu\u2019est-ce que le Dorosz dans la trousse de l\u2019ARC ?", "Un guide pharmacologique de r\u00e9f\u00e9rence utilis\u00e9 par l\u2019ARC pour v\u00e9rifier les interactions m\u00e9dicamenteuses et les posologies lors du monitoring."),
            ("Qu\u2019est-ce que le RCP d\u2019un m\u00e9dicament ?", "Le R\u00e9sum\u00e9 des Caract\u00e9ristiques du Produit, document officiel d\u00e9crivant les propri\u00e9t\u00e9s, indications, contre-indications et effets ind\u00e9sirables du m\u00e9dicament."),
            ("Qu\u2019est-ce que les BPC dans le contexte du monitoring ?", "Les Bonnes Pratiques Cliniques, d\u00e9finies par la d\u00e9cision du 24 novembre 2006, fixant les r\u00e8gles applicables aux recherches biom\u00e9dicales."),
            ("Pourquoi l\u2019ARC ne doit-il jamais rater son rendez-vous de monitoring ?", "Le respect des rendez-vous est essentiel pour maintenir la confiance avec l\u2019\u00e9quipe investigatrice et assurer le bon d\u00e9roulement de l\u2019\u00e9tude."),
            ("Quand peut-on clore un centre par courrier sans visite ?", "Quand il s\u2019agit d\u2019un centre non actif (absence d\u2019inclusion), la cl\u00f4ture peut se faire par simple courrier."),
            ("Que doit inclure le courriel de confirmation de rendez-vous ?", "Date et heure, objectifs, dur\u00e9e, personnes \u00e0 rencontrer (IC, TEC, pharmacien), documents \u00e0 pr\u00e9parer (dossier source, CRF, classeurs), salle et connexion internet."),
            ("Qu\u2019est-ce que la check-list type des consentements ?", "Un outil de l\u2019ARC pour v\u00e9rifier syst\u00e9matiquement la conformit\u00e9 de chaque consentement : signatures, dates, version du document, notification dans le dossier m\u00e9dical."),
            ("Qu\u2019est-ce que le formulaire de comptabilit\u00e9 des UT ?", "Un document tra\u00e7ant la r\u00e9ception, la dispensation, le retour et la destruction des unit\u00e9s de traitement."),
            ("Quelle est la diff\u00e9rence entre non-conformit\u00e9 critique et majeure pour le consentement ?", "Critique : absence de consentement sign\u00e9 ou patient d\u00e9c\u00e9d\u00e9 sans consentement (donn\u00e9es inexploitables). Majeure : absence de date, non sign\u00e9 par l\u2019investigateur, mauvaise version du NIFC."),
            ("Quels sont les documents sp\u00e9cifiques au d\u00e9placement de l\u2019ARC ?", "L\u2019ordre de mission et la copie du courriel de confirmation de rendez-vous."),
            ("Que sont les alertes CleanWeb ?", "Des alertes g\u00e9n\u00e9r\u00e9es par le logiciel E-CRF signalant des EIG d\u00e9clar\u00e9s ou des anomalies dans les donn\u00e9es saisies."),
            ("Comment fonctionne le suivi des EIG apr\u00e8s la visite ?", "L\u2019ARC met \u00e0 jour les tableaux de suivi des EI graves et non graves. En cas de non-conformit\u00e9, un logiciel de tra\u00e7abilit\u00e9 est utilis\u00e9."),
            ("En quoi le monitoring de la pharmacie v\u00e9rifie-t-il le respect de l\u2019aveugle ?", "L\u2019ARC v\u00e9rifie que la dispensation des UT respecte l\u2019aveugle : ni le patient ni l\u2019investigateur ne savent quel traitement est administr\u00e9."),
            ("Pourquoi v\u00e9rifier l\u2019existence des patients inclus ?", "Pour s\u2019assurer que les patients sont r\u00e9els et non fictifs, garantissant l\u2019int\u00e9grit\u00e9 des donn\u00e9es de l\u2019essai."),
            ("Qu\u2019est-ce qu\u2019une analyse interm\u00e9diaire ?", "Une analyse statistique en cours d\u2019essai pouvant montrer une efficacit\u00e9 suffisante (arr\u00eat pour succ\u00e8s) ou une inefficacit\u00e9/toxicit\u00e9 (arr\u00eat pour futilit\u00e9 ou s\u00e9curit\u00e9)."),
            ("Quel est le r\u00f4le du CV dat\u00e9 et sign\u00e9 de l\u2019investigateur dans le classeur ?", "Il atteste des qualifications et comp\u00e9tences de l\u2019investigateur pour mener l\u2019\u00e9tude. Il doit \u00eatre \u00e0 jour dans le classeur investigateur."),
            ("Qu\u2019est-ce que l\u2019engagement de responsabilit\u00e9 du promoteur ?", "Un document sign\u00e9 par le promoteur attestant de ses responsabilit\u00e9s juridiques et financi\u00e8res dans la conduite de l\u2019essai clinique."),
            ("Qu\u2019est-ce que l\u2019engagement de responsabilit\u00e9 de l\u2019investigateur coordonnateur ?", "Un document attestant que l\u2019investigateur coordonnateur s\u2019engage \u00e0 mener l\u2019\u00e9tude conform\u00e9ment au protocole et aux BPC."),
        ]
    },
    {
        "id": "sp_gestion_fc8",
        "filename": "fc8.html",
        "folder": "SP_Gestion",
        "title_h1": "Gestion de projet",
        "title_h2": "R\u00e9glementation sur les \u00e9chantillons biologiques (FC8)",
        "flashcards": [
            ("Qu\u2019est-ce qu\u2019une collection biologique selon l\u2019article 1243-3 du CSP ?", "R\u00e9union, \u00e0 des fins scientifiques, de pr\u00e9l\u00e8vements biologiques effectu\u00e9s sur un groupe de personnes identifi\u00e9es et s\u00e9lectionn\u00e9es en fonction de caract\u00e9ristiques cliniques ou biologiques, ainsi que des d\u00e9riv\u00e9s de ces pr\u00e9l\u00e8vements."),
            ("Une collection biologique peut-elle \u00eatre constitu\u00e9e d\u2019\u00e9chantillons divers et vari\u00e9s ?", "Non, elle doit \u00eatre coh\u00e9rente, par exemple dans le cadre d\u2019une pathologie donn\u00e9e."),
            ("Quelle est la finalit\u00e9 d\u2019une collection biologique ?", "Une finalit\u00e9 scientifique de recherche, et non m\u00e9dicale (de soins)."),
            ("Quelles sont les deux grandes situations de collecte d\u2019\u00e9chantillons biologiques ?", "1) Collecte prospective d\u2019\u00e9chantillons pour la recherche\n2) Utilisation r\u00e9trospective d\u2019\u00e9chantillons d\u00e9j\u00e0 collect\u00e9s."),
            ("Quels sont les types de collecte prospective ?", "\u00c9chantillons du soin requalifi\u00e9s en recherche, \u00e9chantillons collect\u00e9s sp\u00e9cifiquement pour la recherche, et \u00e9chantillons conserv\u00e9s apr\u00e8s une RIPH termin\u00e9e."),
            ("Qu\u2019est-ce qu\u2019un \u00e9chantillon du soin requalifi\u00e9 en recherche ?", "Un reliquat du pr\u00e9l\u00e8vement effectu\u00e9 pour le soin (fond de tube, d\u00e9chet op\u00e9ratoire) que l\u2019on souhaite utiliser \u00e0 des fins scientifiques. C\u2019est une RIPH3."),
            ("Quel type de consentement est requis pour les \u00e9chantillons du soin requalifi\u00e9s ?", "Information et recueil de la non-opposition du patient. Exception : consentement \u00e9crit obligatoire si \u00e9tude g\u00e9n\u00e9tique."),
            ("Comment distingue-t-on RIPH1 et RIPH2 pour les \u00e9chantillons collect\u00e9s sp\u00e9cifiquement ?", "Si risques et contraintes minimes (non ou peu invasif) selon l\u2019arr\u00eat\u00e9 du 12 avril 2018 : RIPH2. Si risques \u00e9lev\u00e9s (invasif, hors arr\u00eat\u00e9) : RIPH1."),
            ("Que pr\u00e9cise l\u2019arr\u00eat\u00e9 du 12 avril 2018 ?", "La liste des \u00e9chantillons biologiques pouvant \u00eatre collect\u00e9s sp\u00e9cifiquement pour la recherche dans le cadre d\u2019une RIPH2."),
            ("Quels sont les pr\u00e9l\u00e8vements non/peu invasifs selon l\u2019arr\u00eat\u00e9 ?", "Sang faible volume (ponction veineuse p\u00e9riph\u00e9rique ou capillaire, volume limit\u00e9 selon le poids), urines, biopsies cutan\u00e9es superficielles (hors visage et plis), \u00e9couvillonnage (col ut\u00e9rin, vagin, \u0153il, nasopharynx)."),
            ("Quels sont les pr\u00e9l\u00e8vements \u00ab suppl\u00e9mentaires \u00bb selon l\u2019arr\u00eat\u00e9 ?", "Expectorations provoqu\u00e9es, tissus/biopsies \u00e9largies du soin, liquide amniotique suppl\u00e9mentaire (\u2264 5 mL total), liquide c\u00e9phalo-rachidien suppl\u00e9mentaire (\u2264 5 mL total)."),
            ("Comment est d\u00e9termin\u00e9 le volume sanguin autoris\u00e9 en RIPH2 ?", "Par un tableau de l\u2019annexe 2 de l\u2019arr\u00eat\u00e9, en fonction du poids de la personne et de son taux d\u2019h\u00e9moglobine."),
            ("Que se passe-t-il pour les \u00e9chantillons conserv\u00e9s apr\u00e8s une RIPH termin\u00e9e ?", "Si le promoteur souhaite les conserver, il faut une d\u00e9claration de collection au MESRI. Sinon, destruction des \u00e9chantillons \u00e0 l\u2019issue de la recherche."),
            ("Qu\u2019est-ce que la requalification d\u2019\u00e9chantillons du soin existants ?", "Utiliser des \u00e9chantillons conserv\u00e9s \u00e0 vis\u00e9e sanitaire (recommandations des soci\u00e9t\u00e9s savantes) pour la recherche, avec information et non-opposition du patient + d\u00e9claration au MESRI."),
            ("Donner un exemple de recommandation de conservation d\u2019\u00e9chantillons \u00e0 vis\u00e9e sanitaire.", "L\u2019INCa (Institut National du Cancer) recommande de conserver les \u00e9chantillons de tissus des patients atteints de lymphome, sarcome ou tumeurs p\u00e9diatriques."),
            ("Que se passe-t-il si le patient ne r\u00e9pond pas au courrier de demande de non-opposition ?", "En l\u2019absence de r\u00e9ponse dans un d\u00e9lai d\u2019un mois, on consid\u00e8re que le patient ne s\u2019est pas oppos\u00e9. Cependant, il est impossible de collecter de nouveaux \u00e9chantillons de fa\u00e7on prospective."),
            ("Qu\u2019est-ce qu\u2019un changement de finalit\u00e9 d\u2019une collection biologique ?", "Utiliser une collection existante avec des objectifs de recherche compl\u00e8tement diff\u00e9rents de ceux initiaux, n\u00e9cessitant l\u2019information et la non-opposition du patient."),
            ("Le changement de finalit\u00e9 n\u00e9cessite-t-il une d\u00e9marche suppl\u00e9mentaire au MESRI ?", "Non, pas de d\u00e9marche suppl\u00e9mentaire n\u00e9cessaire pour le changement de finalit\u00e9."),
            ("Que dit l\u2019article 16-10 du Code civil sur les \u00e9tudes g\u00e9n\u00e9tiques ?", "L\u2019examen des caract\u00e9ristiques g\u00e9n\u00e9tiques ne peut \u00eatre entrepris qu\u2019\u00e0 des fins m\u00e9dicales ou de recherche. Le consentement expr\u00e8s \u00e9crit est requis avant l\u2019examen. Il est r\u00e9vocable sans forme et \u00e0 tout moment."),
            ("Y a-t-il une distinction entre g\u00e9n\u00e9tique constitutionnelle et non constitutionnelle pour les collections ?", "Non, la loi ne fait pas de distinction. Si extraction de mat\u00e9riel g\u00e9n\u00e9tique humain, c\u2019est une \u00e9tude g\u00e9n\u00e9tique."),
            ("Qu\u2019est-ce que la g\u00e9n\u00e9tique constitutionnelle ?", "La g\u00e9n\u00e9tique h\u00e9r\u00e9ditaire qui \u00e9tudie le patrimoine g\u00e9n\u00e9tique d\u2019une personne."),
            ("Quels types d\u2019\u00e9tudes sont consid\u00e9r\u00e9s comme des \u00e9tudes g\u00e9n\u00e9tiques ?", "Identification d\u2019une maladie g\u00e9n\u00e9tique, identification de facteurs de risque g\u00e9n\u00e9tiques, recherche de pr\u00e9dispositions impactant la sant\u00e9, identification de mutations ou r\u00e9arrangements chromosomiques."),
            ("Existe-t-il une d\u00e9rogation au consentement \u00e9crit pour les \u00e9tudes g\u00e9n\u00e9tiques ?", "Oui, pour les patients d\u00e9c\u00e9d\u00e9s n\u2019ayant pas consenti de leur vivant et les patients perdus de vue. La d\u00e9rogation est accord\u00e9e par le CPP."),
            ("Quelles conditions le CPP v\u00e9rifie-t-il pour accorder la d\u00e9rogation g\u00e9n\u00e9tique ?", "Que la personne ne s\u2019\u00e9tait pas oppos\u00e9e \u00e0 l\u2019examen de ses caract\u00e9ristiques g\u00e9n\u00e9tiques, et l\u2019int\u00e9r\u00eat scientifique de la recherche (Article L1131-1-1 du CSP)."),
            ("Qu\u2019est-ce qu\u2019une d\u00e9claration de collection au MESRI ?", "D\u00e9claration obligatoire pour les activit\u00e9s de pr\u00e9paration et conservation d\u2019\u00e9chantillons pour les propres besoins de recherche de l\u2019organisme (num\u00e9ro DC)."),
            ("Qu\u2019est-ce qu\u2019une autorisation de cession ?", "Autorisation n\u00e9cessaire quand l\u2019organisme souhaite c\u00e9der des \u00e9chantillons \u00e0 d\u2019autres organismes de recherche (num\u00e9ro AC)."),
            ("Quels articles du CSP encadrent la d\u00e9claration et l\u2019autorisation de cession ?", "Articles 1243-3 et 1243-4 du Code de la sant\u00e9 publique."),
            ("Qu\u2019est-ce qu\u2019une importation d\u2019\u00e9chantillons biologiques ?", "La r\u00e9ception d\u2019\u00e9chantillons biologiques sur le territoire fran\u00e7ais, soumise \u00e0 autorisation du MESRI."),
            ("Qu\u2019est-ce qu\u2019une exportation d\u2019\u00e9chantillons biologiques ?", "L\u2019envoi d\u2019\u00e9chantillons biologiques depuis le territoire fran\u00e7ais vers l\u2019\u00e9tranger, soumis \u00e0 autorisation du MESRI."),
            ("Quels articles du CSP encadrent l\u2019importation/exportation ?", "Articles 1221-12, 1235-1 et 1245-5 du Code de la sant\u00e9 publique."),
            ("Quelle r\u00e9glementation le transporteur doit-il respecter ?", "La r\u00e9glementation IATA pour le transport des \u00e9chantillons biologiques."),
            ("Quels sont les points cl\u00e9s \u00e0 retenir sur la r\u00e9glementation des \u00e9chantillons biologiques ?", "Diff\u00e9rentes situations de collecte, cas particulier des \u00e9tudes g\u00e9n\u00e9tiques (vigilance, r\u00e8gles strictes), et r\u00e9glementation sp\u00e9cifique (d\u00e9claration, autorisation de cession, import/export)."),
            ("Pour un \u00e9chantillon du soin requalifi\u00e9, peut-on collecter de nouveaux \u00e9chantillons si le patient ne s\u2019oppose pas ?", "Non, en cas de non-opposition par absence de r\u00e9ponse, il n\u2019est pas possible de collecter de nouveaux \u00e9chantillons de fa\u00e7on prospective."),
            ("Quelle est la diff\u00e9rence de consentement entre \u00e9tude g\u00e9n\u00e9tique et non g\u00e9n\u00e9tique pour les \u00e9chantillons requalifi\u00e9s ?", "Non g\u00e9n\u00e9tique : information et non-opposition suffisent. G\u00e9n\u00e9tique : consentement \u00e9crit obligatoire."),
            ("Quel format a le num\u00e9ro de d\u00e9claration de collection ?", "Format DC-AAAA-XXXX, exemple : DC-2019-3637."),
            ("Quel format a le num\u00e9ro d\u2019autorisation de cession ?", "Format AC-AAAA-XXXX, exemple : AC-2019-3818."),
            ("Le consentement pour une \u00e9tude g\u00e9n\u00e9tique doit-il mentionner la finalit\u00e9 ?", "Oui, le consentement mentionne la finalit\u00e9 de l\u2019examen. Il est r\u00e9vocable sans forme et \u00e0 tout moment."),
            ("Que faut-il pr\u00e9voir en plus du consentement standard pour une \u00e9tude g\u00e9n\u00e9tique dans le cadre d\u2019une RIPH ?", "Un consentement \u00e9crit sp\u00e9cifique \u00e0 l\u2019\u00e9tude g\u00e9n\u00e9tique, en plus du consentement pour la RIPH."),
            ("Qu\u2019est-ce qu\u2019un fond de tube en recherche clinique ?", "Le reliquat de sang restant dans un tube apr\u00e8s les analyses de soin, qui peut \u00eatre requalifi\u00e9 pour la recherche."),
            ("Qu\u2019est-ce qu\u2019un d\u00e9chet op\u00e9ratoire dans le contexte des collections biologiques ?", "Un \u00e9chantillon de tissu obtenu lors d\u2019une intervention chirurgicale de soin, qui peut \u00eatre requalifi\u00e9 \u00e0 des fins de recherche."),
            ("Quel cadre r\u00e9glementaire s\u2019applique \u00e0 la conservation d\u2019\u00e9chantillons apr\u00e8s une recherche m\u00e9dicament ?", "Le r\u00e8glement europ\u00e9en pour les recherches m\u00e9dicament, et la l\u00e9gislation RIPH pour les recherches hors m\u00e9dicament."),
            ("Quel volume maximal de liquide amniotique ou c\u00e9phalo-rachidien suppl\u00e9mentaire est autoris\u00e9 en RIPH2 ?", "Le volume total (soin + recherche) ne doit pas d\u00e9passer 5 mL."),
            ("Pourquoi les biopsies cutan\u00e9es du visage et des plis sont-elles exclues de la cat\u00e9gorie peu invasive ?", "Les biopsies du visage et des plis pr\u00e9sentent des risques esth\u00e9tiques et cicatriciels plus importants, donc elles ne sont pas consid\u00e9r\u00e9es comme peu invasives."),
            ("Qu\u2019est-ce qu\u2019une RIPH1 dans le contexte des \u00e9chantillons biologiques ?", "Une recherche interventionnelle comportant des risques et contraintes \u00e9lev\u00e9s (invasifs), n\u00e9cessitant un consentement \u00e9crit et une autorisation de l\u2019ANSM."),
            ("Qu\u2019est-ce qu\u2019une RIPH2 dans le contexte des \u00e9chantillons biologiques ?", "Une recherche interventionnelle \u00e0 risques et contraintes minimes, avec des pr\u00e9l\u00e8vements non ou peu invasifs d\u00e9finis par l\u2019arr\u00eat\u00e9 du 12 avril 2018."),
            ("Qu\u2019est-ce qu\u2019une RIPH3 dans le contexte des \u00e9chantillons biologiques ?", "Une recherche non interventionnelle o\u00f9 l\u2019on requalifie des reliquats du soin (\u00e9chantillons d\u00e9j\u00e0 pr\u00e9lev\u00e9s pour le soin) \u00e0 des fins de recherche. Seule la non-opposition est requise."),
            ("Quelle est la diff\u00e9rence entre collecte prospective et r\u00e9trospective d\u2019\u00e9chantillons ?", "Prospective : \u00e9chantillons collect\u00e9s \u00e0 partir de maintenant pour la recherche. R\u00e9trospective : utilisation d\u2019\u00e9chantillons d\u00e9j\u00e0 collect\u00e9s et conserv\u00e9s."),
            ("Que signifie la conservation d\u2019\u00e9chantillons \u00e0 vis\u00e9e sanitaire ?", "La conservation d\u2019\u00e9chantillons du soin pour le b\u00e9n\u00e9fice futur du patient, recommand\u00e9e par les soci\u00e9t\u00e9s savantes, permettant de revenir sur les \u00e9chantillons si nouvelles d\u00e9couvertes."),
            ("Qu\u2019est-ce que l\u2019INCa ?", "L\u2019Institut National du Cancer, qui recommande notamment la conservation des \u00e9chantillons de tissus des patients atteints de lymphome, sarcome ou tumeurs p\u00e9diatriques."),
            ("Le changement de finalit\u00e9 permet-il de collecter de nouveaux \u00e9chantillons ?", "Non, le changement de finalit\u00e9 ne concerne que les \u00e9chantillons d\u00e9j\u00e0 existants. Il n\u2019est pas possible de collecter de nouveaux \u00e9chantillons de fa\u00e7on prospective."),
            ("Quelle est la diff\u00e9rence entre la non-opposition par r\u00e9ponse et par absence de r\u00e9ponse ?", "Par r\u00e9ponse : le patient r\u00e9pond activement qu\u2019il ne s\u2019oppose pas. Par absence de r\u00e9ponse : apr\u00e8s un mois sans r\u00e9ponse au courrier, on consid\u00e8re qu\u2019il ne s\u2019oppose pas, mais sans possibilit\u00e9 de nouvelle collecte."),
            ("Quel type de pr\u00e9l\u00e8vement sanguin est autoris\u00e9 en RIPH2 ?", "Sang \u00e0 faible volume r\u00e9alis\u00e9 par ponction veineuse p\u00e9riph\u00e9rique ou capillaire, dont le volume ne d\u00e9passe pas la valeur d\u00e9finie en fonction du poids et du taux d\u2019h\u00e9moglobine."),
            ("L\u2019\u00e9couvillonnage nasopharyng\u00e9 est-il consid\u00e9r\u00e9 comme peu invasif ?", "Oui, l\u2019\u00e9couvillonnage du nasopharynx fait partie des pr\u00e9l\u00e8vements non/peu invasifs autoris\u00e9s en RIPH2 selon l\u2019arr\u00eat\u00e9."),
            ("Les expectorations provoqu\u00e9es sont-elles des pr\u00e9l\u00e8vements peu invasifs ou suppl\u00e9mentaires ?", "Ce sont des pr\u00e9l\u00e8vements suppl\u00e9mentaires au sens de la loi, pas des pr\u00e9l\u00e8vements peu invasifs classiques."),
            ("Que faut-il faire quand le promoteur souhaite conserver les \u00e9chantillons apr\u00e8s un essai m\u00e9dicament r\u00e9gi par le r\u00e8glement europ\u00e9en ?", "Il faut faire une d\u00e9claration de collection au MESRI car la conservation post-essai correspond \u00e0 un changement de finalit\u00e9 de l\u2019\u00e9chantillon."),
            ("Quel consentement sp\u00e9cifique est n\u00e9cessaire pour une \u00e9tude g\u00e9n\u00e9tique sur des \u00e9chantillons requalifi\u00e9s ?", "Un consentement \u00e9crit sp\u00e9cifique \u00e0 l\u2019\u00e9tude g\u00e9n\u00e9tique, m\u00eame si la non-opposition suffit pour la requalification en recherche non g\u00e9n\u00e9tique."),
            ("Quel consentement faut-il pour collecter des urines sp\u00e9cifiquement pour la recherche ?", "Un consentement \u00e9crit car c\u2019est un pr\u00e9l\u00e8vement sp\u00e9cifique pour la recherche (RIPH2). Si \u00e9tude g\u00e9n\u00e9tique, un consentement sp\u00e9cifique suppl\u00e9mentaire est requis."),
            ("Quelle est la r\u00e8gle pour les tissus ou biopsies \u00e9largies r\u00e9alis\u00e9es dans le cadre du soin ?", "Ils sont consid\u00e9r\u00e9s comme des pr\u00e9l\u00e8vements suppl\u00e9mentaires et peuvent \u00eatre collect\u00e9s dans le cadre d\u2019une RIPH2."),
            ("Qu\u2019est-ce qu\u2019un \u00e9chantillon collect\u00e9 de fa\u00e7on prospective ?", "Un \u00e9chantillon dont la collecte est planifi\u00e9e \u00e0 l\u2019avance dans le cadre d\u2019un protocole de recherche, par opposition aux \u00e9chantillons d\u00e9j\u00e0 existants."),
            ("Quel est le r\u00f4le de l\u2019ANSM dans les collections biologiques ?", "L\u2019ANSM donne son autorisation ou enregistrement pour les recherches impliquant la collecte d\u2019\u00e9chantillons biologiques, en v\u00e9rifiant la s\u00e9curit\u00e9 des participants."),
            ("Quel est le r\u00f4le du CPP dans les collections biologiques ?", "Le CPP donne un avis favorable sur l\u2019aspect \u00e9thique de la collecte, notamment la protection des personnes, le consentement et l\u2019information des patients."),
            ("Quel est le r\u00f4le de la CNIL dans les collections biologiques ?", "La CNIL v\u00e9rifie que le traitement des donn\u00e9es associ\u00e9es aux \u00e9chantillons respecte les r\u00e8gles de protection des donn\u00e9es personnelles."),
            ("Quels sont les trois types de r\u00e9glementation sp\u00e9cifique aux \u00e9chantillons biologiques ?", "1) D\u00e9claration de collection (DC)\n2) Autorisation de cession (AC)\n3) Autorisation d\u2019importation/exportation."),
            ("Pourquoi le consentement g\u00e9n\u00e9tique est-il r\u00e9vocable ?", "Selon l\u2019article 16-10 du Code civil, le consentement est r\u00e9vocable sans forme et \u00e0 tout moment, pour prot\u00e9ger le droit des personnes sur leurs caract\u00e9ristiques g\u00e9n\u00e9tiques."),
            ("Peut-on r\u00e9aliser un examen g\u00e9n\u00e9tique \u00e0 des fins commerciales ?", "Non, l\u2019examen des caract\u00e9ristiques g\u00e9n\u00e9tiques ne peut \u00eatre entrepris qu\u2019\u00e0 des fins m\u00e9dicales ou de recherche scientifique."),
            ("Quels sont les quatre types de recherches consid\u00e9r\u00e9es comme \u00e9tudes g\u00e9n\u00e9tiques ?", "1) Identification d\u2019une maladie g\u00e9n\u00e9tique\n2) Identification de facteurs de risque g\u00e9n\u00e9tiques\n3) Recherche de pr\u00e9dispositions/susceptibilit\u00e9s\n4) Identification de mutations ou r\u00e9arrangements chromosomiques."),
            ("Quand le consentement est-il requis pour les \u00e9chantillons biologiques collect\u00e9s dans une RIPH1 ?", "Un consentement \u00e9crit est toujours requis pour les RIPH1 car les risques et contraintes sont \u00e9lev\u00e9s."),
            ("Que sont les \u00e9chantillons conserv\u00e9s au d\u00e9cours d\u2019une RIPH ?", "Des \u00e9chantillons collect\u00e9s pendant une recherche impliquant la personne humaine que le promoteur souhaite conserver apr\u00e8s la fin de la recherche pour de futures \u00e9tudes."),
            ("Quel est le lien entre les collections biologiques et les CRB ?", "Les CRB (Centres de Ressources Biologiques) sont les structures qui assurent la collecte, la conservation et la mise \u00e0 disposition des collections biologiques pour la recherche."),
        ]
    },
    {
        "id": "sp_gestion_fc9",
        "filename": "fc9.html",
        "folder": "SP_Gestion",
        "title_h1": "Gestion de projet",
        "title_h2": "D\u00e9marches aupr\u00e8s du MESRI (FC9)",
        "flashcards": [
            ("Quel est l\u2019objectif principal du cours sur les d\u00e9marches aupr\u00e8s du MESRI ?", "Faire le point sur les d\u00e9marches r\u00e9glementaires \u00e0 effectuer aupr\u00e8s du MESRI (Minist\u00e8re de l\u2019Enseignement Sup\u00e9rieur, de la Recherche et de l\u2019Innovation) pour les collections biologiques."),
            ("Quels sont les deux types de d\u00e9marches \u00e0 effectuer aupr\u00e8s du MESRI ?", "1) D\u00e9claration de collection (pour la pr\u00e9paration et conservation \u00e0 des fins de recherche propres)\n2) Autorisation de cession (pour c\u00e9der des \u00e9chantillons \u00e0 des chercheurs ext\u00e9rieurs sans collaboration scientifique)."),
            ("Quand une d\u00e9claration de collection au MESRI est-elle obligatoire ?", "D\u00e8s qu\u2019un organisme conserve des \u00e9chantillons biologiques \u00e0 des fins de recherche, que ce soit pour ses propres activit\u00e9s ou pour des collaborations scientifiques initi\u00e9es par le promoteur."),
            ("Quand l\u2019autorisation de cession est-elle obligatoire ?", "Quand l\u2019organisme souhaite c\u00e9der des \u00e9chantillons \u00e0 des chercheurs ext\u00e9rieurs en dehors de toute collaboration scientifique, en renon\u00e7ant \u00e0 toute propri\u00e9t\u00e9 intellectuelle."),
            ("L\u2019autorisation de cession est-elle toujours obligatoire ?", "Non, elle n\u2019est obligatoire que si l\u2019organisme souhaite r\u00e9aliser des cessions d\u2019\u00e9chantillons."),
            ("Pour quels types de collections la d\u00e9claration au MESRI est-elle requise ?", "Conservation d\u2019\u00e9chantillons \u00e0 l\u2019issue d\u2019une RIPH ou recherche m\u00e9dicament termin\u00e9e (changement de finalit\u00e9), et requalification pour la recherche d\u2019\u00e9chantillons issus du soin."),
            ("Qu\u2019est-ce que CODECOH ?", "Conservation D\u2019\u00c9l\u00e9ments du Corps Humain : une plateforme web permettant aux organismes de soumettre les dossiers de d\u00e9claration et d\u2019autorisation par voie \u00e9lectronique."),
            ("Quelles sont les \u00e9tapes de cr\u00e9ation d\u2019un dossier CODECOH ?", "1) Cr\u00e9ation du num\u00e9ro (DC ou AC)\n2) Saisie \u00e9lectronique + pi\u00e8ces jointes\n3) Soumission apr\u00e8s validation par le repr\u00e9sentant l\u00e9gal\n4) Validation du MESRI (accus\u00e9 sous 1 mois, accept\u00e9 si pas de r\u00e9ponse en 2 mois)."),
            ("Quel est le format du num\u00e9ro de d\u00e9claration de collection ?", "DC-AAAA-XXXX, exemple : DC-2019-2327 pour le CRB d\u2019Henri-Mondor."),
            ("Quel est le format du num\u00e9ro d\u2019autorisation de cession ?", "AC-AAAA-XXXX, exemple : AC-2019-3818."),
            ("Qui est le repr\u00e9sentant l\u00e9gal pour le CRB d\u2019Henri-Mondor ?", "Le directeur de la Direction de la Recherche Clinique de l\u2019Innovation, des Relations avec les Universit\u00e9s et les Organismes de Recherche de l\u2019AP-HP."),
            ("Que contient la Partie I du dossier CODECOH ?", "Renseignements administratifs : statut juridique de l\u2019entit\u00e9 (h\u00f4pital public/priv\u00e9, fondation), organisme, identit\u00e9 du responsable scientifique."),
            ("Que contient la Partie II du dossier CODECOH ?", "Dossier technique : activit\u00e9s, locaux, personnel, mat\u00e9riel de l\u2019organisme charg\u00e9 de la conservation."),
            ("Que contient la Partie III du dossier CODECOH ?", "Renseignements scientifiques (1 page par collection) : r\u00e9sum\u00e9 des objectifs, nature des \u00e9chantillons, modalit\u00e9s d\u2019obtention, statut r\u00e9glementaire, renseignements \u00e9thiques."),
            ("Quelles pi\u00e8ces justificatives doivent \u00eatre fournies au MESRI ?", "Avis favorable du CPP, autorisation/enregistrement ANSM, autorisation CNIL, certificat d\u2019assurance, note d\u2019information, formulaire de consentement ou de non-opposition."),
            ("Le dossier de d\u00e9claration CODECOH est-il statique ou dynamique ?", "Il est dynamique : il doit \u00eatre tenu \u00e0 jour avec des modifications substantielles (ajout/suppression de collections) ou complexes, adress\u00e9es au MESRI par courrier."),
            ("Le MESRI peut-il contr\u00f4ler les d\u00e9clarations ?", "Oui, le MESRI peut effectuer des contr\u00f4les pour v\u00e9rifier la v\u00e9racit\u00e9 des informations, avec des sanctions possibles allant jusqu\u2019\u00e0 l\u2019interdiction de conserver des collections."),
            ("Quelles sont les sp\u00e9cificit\u00e9s du dossier d\u2019autorisation de cession ?", "Description du projet scientifique du destinataire, modalit\u00e9s d\u2019\u00e9tiquetage et anonymisation (totale et d\u00e9finitive), suivi/contrat financier, autorisation du promoteur et du responsable de collection."),
            ("Tous les combien de temps l\u2019autorisation de cession doit-elle \u00eatre renouvel\u00e9e ?", "Tous les 5 ans."),
            ("Quelles sanctions le MESRI peut-il prendre pour une autorisation de cession ?", "Des sanctions allant jusqu\u2019\u00e0 l\u2019interdiction de c\u00e9der des \u00e9chantillons biologiques \u00e0 des chercheurs ext\u00e9rieurs."),
            ("Comment se fait une demande d\u2019importation/exportation d\u2019\u00e9chantillons ?", "Dossier papier envoy\u00e9 en 3 exemplaires au MESRI par lettre recommand\u00e9e avec accus\u00e9 de r\u00e9ception."),
            ("Quel est le d\u00e9lai de validation du MESRI pour l\u2019import/export ?", "Validation par courrier officiel dans un d\u00e9lai de 3 mois. En l\u2019absence de r\u00e9ponse dans les 3 mois : refus."),
            ("Quelle est la dur\u00e9e de validit\u00e9 d\u2019une autorisation d\u2019import/export ?", "5 ans, pour une destination pr\u00e9cise."),
            ("Que contient la Partie I du dossier d\u2019import/export ?", "Renseignements relatifs au demandeur : statut juridique, coordonn\u00e9es de l\u2019organisme, coordonn\u00e9es du responsable de l\u2019activit\u00e9."),
            ("Que contient la Partie II du dossier d\u2019import/export ?", "Programme de recherche : justification de la n\u00e9cessit\u00e9, dur\u00e9e du programme, nombre d\u2019envois pr\u00e9vus, devenir des \u00e9chantillons (g\u00e9n\u00e9ralement d\u00e9truits)."),
            ("Que contient la Partie IV (importation) du dossier ?", "Dans le cas d\u2019un import : nature et origine des \u00e9chantillons, lieu de pr\u00e9l\u00e8vement, modalit\u00e9s du don, conditionnement, conditions de transport, coordonn\u00e9es du fournisseur \u00e9tranger."),
            ("Que contient la Partie V (exportation) du dossier ?", "Nature et origine des \u00e9chantillons, lieu de pr\u00e9l\u00e8vement, modalit\u00e9s du don, conditionnement et \u00e9tiquetage, conditions de transport, coordonn\u00e9es du destinataire \u00e9tranger."),
            ("Quelle attestation doit accompagner le dossier d\u2019import/export ?", "Une attestation sur l\u2019honneur du responsable indiquant que les patients ont donn\u00e9 leur consentement et qu\u2019aucun paiement n\u2019a \u00e9t\u00e9 allou\u00e9 aux donneurs."),
            ("Que risque-t-on si l\u2019autorisation d\u2019import/export n\u2019est pas obtenue ?", "Le colis contenant les \u00e9chantillons biologiques sera bloqu\u00e9 \u00e0 la douane au d\u00e9part ou \u00e0 l\u2019arriv\u00e9e en France."),
            ("Le don d\u2019\u00e9chantillons biologiques en France est-il soumis \u00e0 des r\u00e8gles ?", "Oui, en France le don doit \u00eatre gratuit, anonyme et consenti."),
            ("L\u2019autorisation d\u2019import/export est-elle renouvelable ?", "Selon le cours oral, elle serait non renouvelable (information contradictoire dans les supports)."),
            ("Que diff\u00e9rencie le dossier de d\u00e9claration du dossier d\u2019autorisation ?", "D\u00e9claration : pour les activit\u00e9s de recherche et collaborations scientifiques pour les propres besoins. Autorisation : pour les activit\u00e9s de cession sans collaboration scientifique."),
            ("Qu\u2019est-ce que le MESRI ?", "Le Minist\u00e8re de l\u2019Enseignement Sup\u00e9rieur, de la Recherche et de l\u2019Innovation."),
            ("Quelle est la diff\u00e9rence entre d\u00e9claration et autorisation de collection sur CODECOH ?", "La d\u00e9claration concerne la conservation pour ses propres besoins (DC). L\u2019autorisation concerne la cession \u00e0 d\u2019autres organismes (AC). Ce sont deux dossiers \u00e9lectroniques diff\u00e9rents."),
            ("Comment le MESRI valide-t-il un dossier CODECOH ?", "Accus\u00e9 de r\u00e9ception sous un mois. Si absence de r\u00e9ponse dans un d\u00e9lai de 2 mois, le dossier est r\u00e9put\u00e9 accept\u00e9."),
            ("Pourquoi l\u2019anonymisation doit-elle \u00eatre totale et d\u00e9finitive pour l\u2019autorisation de cession ?", "Le MESRI doit s\u2019assurer qu\u2019il ne sera pas possible de retrouver le patient source lors de la cession \u00e0 des organismes ext\u00e9rieurs."),
            ("Qu\u2019est-ce que le contrat financier dans le dossier d\u2019autorisation de cession ?", "Un contrat permettant au destinataire de rembourser les frais engag\u00e9s par l\u2019organisme pour la collecte, pr\u00e9paration et conservation des \u00e9chantillons c\u00e9d\u00e9s."),
            ("Quelles sont les \u00e9tudes g\u00e9n\u00e9tiques selon l\u2019article 16-10 du Code civil ?", "L\u2019examen des caract\u00e9ristiques g\u00e9n\u00e9tiques d\u2019une personne, ne pouvant \u00eatre entrepris qu\u2019\u00e0 des fins m\u00e9dicales ou de recherche scientifique, avec consentement \u00e9crit pr\u00e9alable."),
            ("Pour les collections biologiques, quand parle-t-on d\u2019\u00e9tude g\u00e9n\u00e9tique ?", "D\u00e8s qu\u2019il y a extraction de mat\u00e9riel g\u00e9n\u00e9tique humain, sans distinction entre g\u00e9n\u00e9tique constitutionnelle et non constitutionnelle."),
            ("Quelle d\u00e9rogation existe pour les patients d\u00e9c\u00e9d\u00e9s dans les \u00e9tudes g\u00e9n\u00e9tiques ?", "D\u00e9rogation possible (article L1131-1-1 du CSP) pour les patients d\u00e9c\u00e9d\u00e9s ou perdus de vue n\u2019ayant pas consenti, accord\u00e9e par le CPP apr\u00e8s v\u00e9rification de l\u2019absence d\u2019opposition et de l\u2019int\u00e9r\u00eat scientifique."),
            ("Quels sont les articles du CSP encadrant la d\u00e9claration de collection ?", "Articles 1243-3 et 1243-4 du Code de la sant\u00e9 publique."),
            ("Quels sont les articles du CSP encadrant l\u2019importation/exportation ?", "Articles 1221-12, 1235-1 et 1245-5 du Code de la sant\u00e9 publique."),
            ("Quelle r\u00e9glementation de transport doit \u00eatre respect\u00e9e pour les \u00e9chantillons biologiques ?", "La r\u00e9glementation IATA (Association Internationale du Transport A\u00e9rien) pour le transport des \u00e9chantillons biologiques."),
            ("Quel est le r\u00e9sum\u00e9 des deux d\u00e9marches CODECOH ?", "D\u00e9claration : activit\u00e9s de recherche et collaborations scientifiques \u2192 dossier \u00e9lectronique DC. Autorisation : activit\u00e9s de cession sans collaboration \u2192 dossier \u00e9lectronique AC. Communication simplifi\u00e9e avec le MESRI."),
            ("Quel est le r\u00e9sum\u00e9 du cours sur l\u2019import/export ?", "Deux activit\u00e9s diff\u00e9rentes (import et export) avec un dossier identique \u00e0 fournir au MESRI, autorisation indispensable sous peine de blocage en douane, valable 5 ans pour une destination pr\u00e9cise."),
            ("Quelles modifications substantielles peut-on faire sur un dossier CODECOH ?", "Rajouter de nouvelles collections, en supprimer certaines qui n\u2019existent plus (d\u00e9truites ou transf\u00e9r\u00e9es), ou effectuer des modifications complexes n\u00e9cessitant de reprendre le dossier."),
            ("Comment les modifications sont-elles communiqu\u00e9es au MESRI ?", "Par courrier indiquant le num\u00e9ro de la d\u00e9claration et la description des modifications. Pour les modifications tr\u00e8s complexes, on reprend le dossier CODECOH et on refait la proc\u00e9dure de validation."),
            ("Pourquoi l\u2019autorisation du promoteur est-elle obligatoire pour l\u2019autorisation de cession ?", "Parce que les \u00e9chantillons ont \u00e9t\u00e9 initialement collect\u00e9s dans le cadre d\u2019un projet dont le promoteur est responsable. Son accord est n\u00e9cessaire pour toute utilisation ult\u00e9rieure."),
            ("Que signifie l\u2019absence de r\u00e9ponse du MESRI en 2 mois pour CODECOH ?", "Le dossier est r\u00e9put\u00e9 accept\u00e9 (principe du silence vaut acceptation)."),
            ("Que signifie l\u2019absence de r\u00e9ponse du MESRI en 3 mois pour l\u2019import/export ?", "Le dossier est refus\u00e9 (principe du silence vaut refus pour l\u2019import/export)."),
            ("Quelle est la diff\u00e9rence de principe entre CODECOH et import/export pour le silence du MESRI ?", "CODECOH : silence = acceptation (2 mois). Import/export : silence = refus (3 mois). Les deux d\u00e9marches ont des r\u00e8gles oppos\u00e9es."),
            ("Quelle est l\u2019obligation du responsable de la recherche avant les travaux sur patients d\u00e9c\u00e9d\u00e9s ?", "Il doit consulter un CPP qui s\u2019assure que la personne ne s\u2019\u00e9tait pas oppos\u00e9e et qui \u00e9met un avis sur l\u2019int\u00e9r\u00eat scientifique."),
            ("L\u2019autorisation d\u2019import/export est-elle pour une destination g\u00e9n\u00e9rale ou pr\u00e9cise ?", "Pour une destination pr\u00e9cise. Chaque nouvelle destination n\u00e9cessite une nouvelle autorisation."),
            ("Le dossier d\u2019import et d\u2019export est-il diff\u00e9rent ?", "Non, c\u2019est un dossier identique \u00e0 fournir au MESRI pour les deux types d\u2019activit\u00e9s."),
            ("Quel est le contenu de l\u2019attestation sur l\u2019honneur pour l\u2019import/export ?", "Le responsable atteste que les \u00e9chantillons ont \u00e9t\u00e9 pr\u00e9lev\u00e9s et collect\u00e9s avec le consentement pr\u00e9alable des patients, sans aucun paiement, et que le donneur a \u00e9t\u00e9 inform\u00e9 et accepte l\u2019utilisation en recherche."),
            ("Les deux dossiers CODECOH (DC et AC) sont-ils des dossiers papier ?", "Non, ce sont deux dossiers \u00e9lectroniques soumis via la plateforme CODECOH, contrairement au dossier d\u2019import/export qui est papier."),
            ("Combien d\u2019exemplaires papier faut-il envoyer pour le dossier d\u2019import/export ?", "3 exemplaires envoy\u00e9s au MESRI par lettre recommand\u00e9e avec accus\u00e9 de r\u00e9ception."),
            ("Quels renseignements \u00e9thiques sont inclus dans la Partie III du dossier CODECOH ?", "Les modalit\u00e9s du recueil du consentement du patient ou de sa non-opposition, avec les pi\u00e8ces justificatives correspondantes."),
            ("Quel est le r\u00f4le du repr\u00e9sentant l\u00e9gal dans la soumission CODECOH ?", "Il valide la soumission en pr\u00e9parant un courrier attestant de la v\u00e9racit\u00e9 des informations saisies."),
            ("Qu\u2019est-ce que le CRB d\u2019Henri-Mondor ?", "Le Centre de Ressources Biologiques de l\u2019h\u00f4pital Henri-Mondor, qui conserve des collections biologiques \u00e0 des fins de recherche (DC-2019-2327, AC-2019-3818)."),
            ("Quelles sont les conditions de transport pour l\u2019import/export d\u2019\u00e9chantillons ?", "Le transporteur doit respecter la r\u00e9glementation IATA, avec un conditionnement et un \u00e9tiquetage conformes pour les mati\u00e8res biologiques."),
            ("Le don d\u2019\u00e9chantillons biologiques peut-il \u00eatre r\u00e9mun\u00e9r\u00e9 en France ?", "Non, en France le don doit \u00eatre gratuit. Aucun paiement ne peut \u00eatre allou\u00e9 aux donneurs."),
            ("Qu\u2019est-ce que le devenir des \u00e9chantillons export\u00e9s ?", "Les \u00e9chantillons export\u00e9s sont g\u00e9n\u00e9ralement d\u00e9truits \u00e0 la fin du programme de recherche, comme indiqu\u00e9 dans le dossier d\u2019export."),
            ("Quels \u00e9l\u00e9ments du programme de recherche figurent dans le dossier d\u2019import/export ?", "Justification de la n\u00e9cessit\u00e9 de l\u2019import/export, dur\u00e9e du programme, nombre d\u2019envois pr\u00e9vus, et devenir des \u00e9chantillons."),
            ("Qu\u2019est-ce que la nature et l\u2019origine des \u00e9chantillons dans le dossier d\u2019import/export ?", "La description du type d\u2019\u00e9chantillon biologique (sang, tissu, ADN, etc.) et de sa provenance (lieu de pr\u00e9l\u00e8vement, conditions de collecte)."),
            ("Comment les modalit\u00e9s d\u2019\u00e9tiquetage sont-elles encadr\u00e9es pour la cession ?", "L\u2019anonymisation doit \u00eatre totale et d\u00e9finitive. Le MESRI doit s\u2019assurer qu\u2019il ne sera pas possible de retrouver le patient source."),
            ("Qu\u2019est-ce que IATA ?", "L\u2019Association Internationale du Transport A\u00e9rien, dont la r\u00e9glementation encadre le transport d\u2019\u00e9chantillons biologiques par voie a\u00e9rienne."),
            ("Pourquoi le dossier CODECOH est-il qualifi\u00e9 de dynamique ?", "Parce qu\u2019il doit \u00eatre r\u00e9guli\u00e8rement mis \u00e0 jour : ajout de nouvelles collections, suppression de collections d\u00e9truites ou transf\u00e9r\u00e9es, modifications substantielles ou complexes."),
            ("Quels types d\u2019organismes peuvent \u00eatre d\u00e9clarants sur CODECOH ?", "\u00c9tablissements de sant\u00e9 publics ou priv\u00e9s, fondations de recherche, ou tout organisme conservant des collections biologiques \u00e0 des fins de recherche."),
            ("Quelle est la dur\u00e9e du programme de recherche \u00e0 indiquer dans le dossier d\u2019import/export ?", "La dur\u00e9e pr\u00e9vue du programme de recherche pour lequel les \u00e9chantillons sont import\u00e9s ou export\u00e9s."),
            ("Quelle est la diff\u00e9rence de format entre les dossiers CODECOH et import/export ?", "CODECOH : dossier \u00e9lectronique soumis via la plateforme web. Import/export : dossier papier envoy\u00e9 en 3 exemplaires par lettre recommand\u00e9e."),
            ("Que se passe-t-il si des modifications tr\u00e8s complexes sont n\u00e9cessaires sur un dossier CODECOH ?", "Il est possible de reprendre le dossier CODECOH et d\u2019effectuer les modifications directement dessus, puis de refaire la proc\u00e9dure de validation dans son int\u00e9gralit\u00e9."),
            ("Quelle est l\u2019importance du num\u00e9ro DC ou AC dans le suivi des collections ?", "Ces num\u00e9ros uniques permettent d\u2019identifier chaque d\u00e9claration ou autorisation, de tracer les modifications et de communiquer efficacement avec le MESRI."),
            ("Quelles sanctions le MESRI peut-il prendre pour la d\u00e9claration de collection ?", "Des sanctions allant jusqu\u2019\u00e0 l\u2019interdiction de conserver des collections d\u2019\u00e9chantillons biologiques."),
            ("En quoi la d\u00e9marche de d\u00e9claration CODECOH simplifie-t-elle la communication ?", "Les deux dossiers sont \u00e9lectroniques, la soumission est d\u00e9mat\u00e9rialis\u00e9e via la plateforme CODECOH, et la validation par le MESRI est automatis\u00e9e (silence = acceptation en 2 mois)."),
            ("Que doit faire un organisme qui d\u00e9truit une collection biologique ?", "Il doit mettre \u00e0 jour son dossier CODECOH en supprimant la collection d\u00e9truite, via une modification substantielle adress\u00e9e au MESRI."),
            ("Le transfert d\u2019une collection \u00e0 un autre organisme n\u00e9cessite-t-il une mise \u00e0 jour CODECOH ?", "Oui, le transfert d\u2019une collection vers un autre organisme n\u00e9cessite une modification du dossier CODECOH pour supprimer la collection transf\u00e9r\u00e9e."),
            ("Quelle est la finalit\u00e9 du contrat financier dans l\u2019autorisation de cession ?", "Permettre au destinataire de rembourser les frais de collecte, pr\u00e9paration et conservation engag\u00e9s par l\u2019organisme c\u00e9dant, sans constituer un paiement pour les \u00e9chantillons eux-m\u00eames."),
            ("Pourquoi l\u2019autorisation du promoteur est-elle requise pour toute cession ?", "Parce que les \u00e9chantillons ont \u00e9t\u00e9 initialement collect\u00e9s dans le cadre d\u2019un projet dont le promoteur est juridiquement responsable."),
            ("Quel est le d\u00e9lai d\u2019envoi de l\u2019accus\u00e9 de r\u00e9ception pour un dossier CODECOH ?", "L\u2019accus\u00e9 de r\u00e9ception est envoy\u00e9 sous un mois apr\u00e8s la soumission du dossier."),
        ]
    },
]
